function triggerInstall(){
  if(!_installPrompt) return;
  _installPrompt.prompt();
  _installPrompt.userChoice.then(function(r){
    if(r.outcome === 'accepted') dismissInstall();
    _installPrompt = null;
  });
}

function dismissInstall(){
  var b = document.getElementById('install-banner');
  if(b) b.remove();
  try{ localStorage.setItem('install_dismissed','1'); }catch(e){}
}

// Don't show if already dismissed or installed
window.addEventListener('appinstalled', function(){ dismissInstall(); });

