function sha256(msg){
  return crypto.subtle.digest('SHA-256',new TextEncoder().encode(msg)).then(function(buf){
    return Array.from(new Uint8Array(buf)).map(function(b){return b.toString(16).padStart(2,'0')}).join('');
  });
}

