var _loginAttempts=0,_loginLocked=false;
function checkLoginRateLimit(){
  if(_loginLocked){showLoginError('Trop de tentatives. Attendez 30s.');return false;}
  _loginAttempts++;
  if(_loginAttempts>=5){_loginLocked=true;setTimeout(function(){
  if(typeof loadTheme!=="undefined") loadTheme();_loginLocked=false;_loginAttempts=0;},30000);}
  return true;
}
function showLoginError(msg){
  var el=document.getElementById('lerr');
  if(el){el.textContent=msg||'Pseudo ou PIN incorrect.';el.style.display='block';}
}

function swTab(t){
  document.querySelectorAll('.ltab').forEach(function(el,i){
    el.classList.toggle('active',(i===0&&t==='login')||(i===1&&t==='reg'));
  });
  document.getElementById('lf').style.display=t==='login'?'':'none';
  document.getElementById('rf').style.display=t==='reg'?'':'none';
}

function doLogin(){
  if(!checkLoginRateLimit())return;
  var u=sanitize(gVal('lu'),50);
  var p=gVal('lp');
  if(!u||!p){showLoginError('Pseudo et PIN requis.');return;}
  showLoginError('Connexion en cours...');
  document.getElementById('lerr').style.color='var(--teal2)';

  sha256(p).then(function(hash){
    // 1. Vérifier PIN directement en base (jamais exposé dans membres_public)
    fetch(SB_URL+'/rest/v1/membres?username=eq.'+encodeURIComponent(u)+'&select=id,pin,status&limit=1',{
      headers:{'apikey':SB_KEY,'Authorization':'Bearer '+SB_KEY}
    }).then(function(r){return r.json();}).then(function(rows){
      var row=rows&&rows[0];
      if(!row){
        // Vérifier si candidature en attente
        sbLoad().then(function(){
          var pm=(DB.pendingMembers||[]).find(function(x){return x.username.toLowerCase()===u.toLowerCase();});
          document.getElementById('lerr').style.color='var(--red3)';
          showLoginError(pm?'Candidature en attente d\'approbation.':'Pseudo ou PIN incorrect.');
        });
        return;
      }
      if(!(row.pin===hash||row.pin===p)){
        document.getElementById('lerr').style.color='var(--red3)';
        showLoginError('Pseudo ou PIN incorrect.');
        return;
      }
      if(row.status==='attente'){
        document.getElementById('lerr').style.color='var(--red3)';
        showLoginError('Candidature en attente d\'approbation.');
        return;
      }
      // 2. Charger toutes les données (membres_public, pas de PINs)
      sbLoad().then(function(){
        var m=DB.members.find(function(m){return m.id===row.id;});
        if(!m){showLoginError('Erreur lors de la connexion.');return;}
        m.pin=row.pin; // Stocker uniquement son propre PIN
        _setHRRole(row.role||m.role); // Verrouiller le rôle vérifié en base
        CU=m;
        try{sessionStorage.setItem('fs_session', JSON.stringify({username:m.username, pin:p}));localStorage.setItem('fs_session_backup', JSON.stringify({username:m.username, pin:p}));}catch(e){}
        document.getElementById('ls').style.display='none';
        document.getElementById('app').style.display='flex';
        if(typeof applyMobileLayout!=='undefined')applyMobileLayout();
        updSB();
        if(CU&&CU.theme&&typeof applyTheme!=='undefined')applyTheme(CU.theme);
        addNavBadge('nav-for','badge-forum');addNavBadge('nav-form','badge-form');addNavBadge('nav-vote','badge-vote');addNavBadge('nav-grp','badge-grp');addNavBadge('nav-cal','badge-cal');addNavBadge('nav-home','badge-home');
        go('home');
        startRealtime();
        initServiceWorker();
        setTimeout(subscribePush, 3000);
        startPresence();
      });
    }).catch(function(){
      showLoginError('Serveur inaccessible. Vérifiez votre connexion.');
      document.getElementById('lerr').style.color='var(--red3)';
    });
  });
}
function doRegister(){
  var u=sanitize(gVal('ru'),50);
  var p=gVal('rpin');
  var p2=gVal('rpin2');
  var msg=sanitize(gVal('rmsg'),300);
  var err=document.getElementById('rerr');
  if(!u||!p){err.textContent='Pseudo et PIN requis.';err.style.display='block';return;}
  if(p!==p2){err.textContent='Les PINs ne correspondent pas.';err.style.display='block';return;}
  if(!/^[0-9]{4,8}$/.test(p)){err.textContent='PIN: 4 à 8 chiffres.';err.style.display='block';return;}
  // Vérifier doublon dans les membres déjà chargés
  if(DB.members.find(function(m){return m.username.toLowerCase()===u.toLowerCase()})||
     (DB.pendingMembers||[]).find(function(m){return m.username.toLowerCase()===u.toLowerCase()})){
    err.textContent='Ce pseudo est déjà utilisé.';err.style.color='var(--red3)';err.style.display='block';return;
  }
  err.textContent='Envoi en cours...';err.style.color='var(--teal2)';err.style.display='block';
  sha256(p).then(function(hash){
    var pending={
      id:'p'+Date.now(), username:u, pin:hash,
      role:'recrue', status:'attente', sanguin:false, grandChampion:false,
      joinDate:nowDate(), note:msg, units:[], avatar:''
    };
    sbSaveMember(pending).then(function(){
      err.style.display='none';
      alert('\u2705 Candidature envoy\u00e9e ! Un officier examinera votre demande.');
      swTab('login');
    }).catch(function(e){
      console.warn('[Register]',e);
      err.textContent='Erreur serveur. R\u00e9essayez dans quelques secondes.';
      err.style.color='var(--red3)';
    });
  });
}

