// TEMPS RÉEL — Supabase Realtime WebSocket + polling fallback
// ════════════════════════════════════════════════════════════════
var _pollTimer=null;
var _pollHash='';
var _realtimeWs=null;
var _realtimeRef=0;
var _realtimeHeartbeat=null;

function _dataHash(){
  try{
    var wars=DB.voteWars||[];
    var members=DB.members||[];
    // Hash incluant le contenu des votes (pas juste le nombre)
    return wars.length+'|'+members.length+'|'
      +wars.map(function(w){
        var voteStr=Object.keys(w.votes||{}).sort().map(function(k){
          return k+'='+((w.votes[k]&&w.votes[k].vote)||'');
        }).join(';');
        return w.id+':'+(w.status||'')+':'+voteStr;
      }).join(',')
      +'|'+members.map(function(m){return m.id+':'+m.status;}).join(',');
  }catch(e){return '';}
}

// Pages jamais re-rendues automatiquement (rédaction longue)
var POLL_SKIP_PAGES=['for','form'];

function _userIsTyping(){
  var active=document.activeElement;
  if(!active)return false;
  var tag=active.tagName.toLowerCase();
  return tag==='input'||tag==='textarea'||tag==='select'||active.contentEditable==='true';
}

function _rerender(){
  // Badges nav — toujours safe
  addNavBadge('nav-for','badge-forum');
  addNavBadge('nav-form','badge-form');
  addNavBadge('nav-vote','badge-vote');
  addNavBadge('nav-grp','badge-grp');
  addNavBadge('nav-cal','badge-cal');
  addNavBadge('nav-home','badge-home');
  // Ne jamais re-render si modal ouvert, saisie active, ou page de rédaction
  var modal=document.getElementById('mo');
  if(modal&&modal.style.display!=='none')return;
  if(_userIsTyping())return;
  if(POLL_SKIP_PAGES.indexOf(CP)>=0)return;
  var fns={home:pgHome,mbr:pgMbr,unit:pgUnit,grp:pgGrp,vote:pgVote,
           for:pgFor,form:pgForm,cal:pgCal,rec:pgRec,param:pgParam,
           profil:pgProfil,stats:pgStats,rank:pgRank,planning:pgPlanning,hier:pgHierarchy,rh:pgRH};
  var fn=fns[CP];
  if(fn){
    var content=document.getElementById('content');
    if(content){content.innerHTML=fn();postGo(CP);}
  }
}

// ── Supabase Realtime WebSocket ───────────────────────────────
var _realtimeDebounce=null;

function _triggerReload(){
  // Debounce 300ms : évite les reloads en rafale si plusieurs events arrivent ensemble
  if(_realtimeDebounce) clearTimeout(_realtimeDebounce);
  _realtimeDebounce=setTimeout(function(){
    _realtimeDebounce=null;
    if(!CU)return;
    console.log('[Realtime] → reload+render');
    sbLoad().then(function(){
      _rerender(); // toujours re-render après un event Realtime
    }).catch(function(e){ console.warn('[Realtime] reload err',e); });
  },300);
}

// ── Présence en ligne ─────────────────────────────────────────
function pingPresence(){
  if(!CU) return;
  SB.from('presence').upsert({
    membre_id: CU.id,
    username: CU.username,
    last_seen: new Date().toISOString()
  }).catch(function(e){ console.warn('[presence]', e); });
}

function startPresence(){
  pingPresence(); // ping immédiat
  setInterval(pingPresence, 60*1000); // puis toutes les 60s
}


function startRealtime(){
  stopRealtime();
  var wsUrl='wss://xwtwmteqbmvwqjyicgal.supabase.co/realtime/v1/websocket?apikey='+SB_KEY+'&vsn=1.0.0';
  try{ _realtimeWs=new WebSocket(wsUrl); }
  catch(e){
    console.warn('[Realtime] WS non supporté, fallback polling');
    startPolling(); return;
  }

  _realtimeWs.onopen=function(){
    console.log('[Realtime] ✓ Connecté');
    _realtimeRef++;
    // Un seul canal "realtime:fs" avec 3 subscriptions postgres_changes
    _realtimeWs.send(JSON.stringify({
      topic:'realtime:fs',
      event:'phx_join',
      payload:{
        config:{
          broadcast:{self:false},
          presence:{key:''},
          postgres_changes:[
            {event:'*',schema:'public',table:'vote_wars'},
            {event:'*',schema:'public',table:'membres'},
            {event:'*',schema:'public',table:'groupes'},
            {event:'*',schema:'public',table:'house_settings'}
          ]
        }
      },
      ref:String(_realtimeRef)
    }));
    // Heartbeat toutes les 25s
    _realtimeHeartbeat=setInterval(function(){
      if(_realtimeWs&&_realtimeWs.readyState===1){
        _realtimeRef++;
        _realtimeWs.send(JSON.stringify({
          topic:'phoenix',event:'heartbeat',payload:{},ref:String(_realtimeRef)
        }));
      }
    },25000);
  };

  _realtimeWs.onmessage=function(e){
    try{
      var msg=JSON.parse(e.data);
      var ev=msg.event;
      var topic=msg.topic||'';
      // Ignorer les messages système phoenix
      if(topic==='phoenix') return;
      // Ignorer présence
      if(ev==='presence_state'||ev==='presence_diff'||ev==='phx_close') return;
      // phx_reply = ack d'abonnement (pas de données) — ignorer sauf si payload contient des données
      if(ev==='phx_reply'){
        // Vérifier si c'est un ack d'abonnement réussi
        var status=msg.payload&&msg.payload.status;
        if(status==='ok') console.log('[Realtime] ✓ Abonné:',topic);
        return;
      }
      // postgres_changes et INSERT/UPDATE/DELETE = changement de données
      var tbl=(msg.payload&&msg.payload.data&&msg.payload.data.table)||'';
      console.log('[Realtime] ← table:',tbl,'event:',ev);
      // Reload ciblé par table — évite de recharger les 13 tables à chaque event
      if(tbl==='house_settings'){
        var rec=msg.payload&&msg.payload.data&&msg.payload.data.record;
        if(rec&&(rec.key==='hill_king'||rec.key==='hill_bg')){
          if(rec.key==='hill_king') DB.hillKing=rec.value||{};
          if(rec.key==='hill_bg') DB.hillBg=rec.value||'';
          var hw=document.getElementById('hill-widget');
          if(hw){var hn=document.createElement('div');hn.innerHTML=hillHTML();hw.parentNode.replaceChild(hn.firstChild,hw);}
        }
        // Autres clés settings : reload settings uniquement
        if(rec&&rec.key!=='hill_king'&&rec.key!=='hill_bg'){
          SB.from('house_settings').get().then(function(rows){
            var r=rows||[];
            var s=(r.find(function(x){return x.key==='main';})||{}).value||{};
            DB.houseName=s.house_name||DB.houseName;
            DB.minMastery=s.min_mastery||DB.minMastery;
            DB.activeWarId=s.active_war_id||null;
            DB.metaUnits=((r.find(function(x){return x.key==='meta_units';})||{}).value)||[];
            DB.rhUsers=((r.find(function(x){return x.key==='rh_users';})||{}).value)||[];
            DB.rhData=((r.find(function(x){return x.key==='rh_data';})||{}).value)||{};
            DB.builderConfig=((r.find(function(x){return x.key==='builder_config';})||{}).value)||null;
            DB.hillKing=((r.find(function(x){return x.key==='hill_king';})||{}).value)||{};
            DB.hillBg=((r.find(function(x){return x.key==='hill_bg';})||{}).value)||'';
            DB.hillHistory=((r.find(function(x){return x.key==='hill_history';})||{}).value)||[];
            _rerender();
          }).catch(function(e){console.warn('[Realtime] settings reload err',e);});
        }
        return;
      }
      if(tbl==='vote_wars'){
        SB.from('vote_wars').get().then(function(rows){
          DB.voteWars=(rows||[]).map(sbWarToLocal);
          _rerender();
        }).catch(function(e){console.warn('[Realtime] vote_wars reload err',e);});
        return;
      }
      if(tbl==='membres'){
        SB.from('membres_public').get().then(function(rows){
          var all=(rows||[]).map(sbMemberToLocal);
          DB.members=all.filter(function(m){return m.status!=='attente';});
          DB.guestMembers=DB.members.filter(function(m){return m.isGuest;});
          DB.pendingMembers=all.filter(function(m){return m.status==='attente';});
          // Vérifier que le compte connecté existe toujours
          if(CU&&!DB.members.find(function(m){return m.id===CU.id;})){
            console.warn('[Realtime] Compte supprimé — déconnexion');
            doLogout(); return;
          }
          _rerender();
        }).catch(function(e){console.warn('[Realtime] membres reload err',e);});
        return;
      }
      if(tbl==='groupes'){
        SB.from('groupes').get().then(function(rows){
          DB.groups=(rows||[]).map(sbGroupToLocal);
          _rerender();
        }).catch(function(e){console.warn('[Realtime] groupes reload err',e);});
        return;
      }
      if(tbl==='trainings'){
        SB.from('trainings').get().then(function(rows){
          DB.trainings=(rows||[]).map(sbTrainingToLocal);
          _rerender();
        }).catch(function(e){console.warn('[Realtime] trainings reload err',e);});
        return;
      }
      if(tbl==='seasons'){
        SB.from('seasons').get().then(function(rows){
          DB.seasons=(rows||[]);
          _rerender();
        }).catch(function(e){console.warn('[Realtime] seasons reload err',e);});
        return;
      }
      // Fallback pour toute autre table non gérée
      _triggerReload();
    }catch(ex){ console.warn('[Realtime] parse err',ex); }
  };

  _realtimeWs.onerror=function(){
    console.warn('[Realtime] Erreur WS — fallback polling');
    stopRealtime();
    setTimeout(function(){ if(CU) startPolling(); },5000);
  };

  _realtimeWs.onclose=function(ev){
    console.log('[Realtime] Déconnecté (code:'+ev.code+')');
    clearInterval(_realtimeHeartbeat);
    _realtimeHeartbeat=null;
    // Reconnexion auto sauf déconnexion volontaire (code 1000)
    if(CU&&ev.code!==1000){
      setTimeout(function(){ if(CU) startRealtime(); },3000);
    }
  };
}

function stopRealtime(){
  clearInterval(_realtimeHeartbeat);
  _realtimeHeartbeat=null;
  if(_realtimeWs){
    _realtimeWs.onclose=null; // éviter la reconnexion auto
    _realtimeWs.close();
    _realtimeWs=null;
  }
}

// Polling fallback (si Realtime WS indisponible)
function startPolling(){
  stopPolling();
  _pollHash=_dataHash();
  _pollTimer=setInterval(function(){
    if(!CU||!SB_READY)return;
    sbLoad().then(function(){
      var newHash=_dataHash();
      if(newHash===_pollHash)return;
      _pollHash=newHash;
      _rerender();
    }).catch(function(){});
  },20000);
}

function stopPolling(){
  if(_pollTimer){clearInterval(_pollTimer);_pollTimer=null;}
}


