function openGlobalSearch(){
  var html='<div><input class="fi" id="gs-input" placeholder="Rechercher membre, sujet, fiche..." oninput="renderSearchResults(this.value)" autofocus style="font-size:15px;padding:12px 16px"></div><div id="gs-results" style="margin-top:12px;max-height:60vh;overflow-y:auto"></div>';
  OM('🔍 Recherche globale',html,[{lbl:'Fermer',cls:'bol',fn:CM}]);
  setTimeout(function(){var el=document.getElementById('gs-input');if(el)el.focus();},100);
}
function renderSearchResults(q){
  var res=document.getElementById('gs-results');if(!res)return;
  if(!q||q.length<2){res.innerHTML='<div class="td tsm" style="padding:8px">Tapez au moins 2 caractères...</div>';return;}
  q=q.toLowerCase();var results=[];
  (DB.members||[]).forEach(function(m){if(m.username.toLowerCase().indexOf(q)>=0)results.push({type:'Membre',title:m.username,sub:RN[m.role]||m.role,action:function(){CM();go('mbr');}});});
  (DB.forumThreads||[]).filter(function(t){return typeof TAG_LBL!=='undefined'&&Object.keys(TAG_LBL).indexOf(t.tag)>=0;}).forEach(function(t){if(t.title.toLowerCase().indexOf(q)>=0)results.push({type:'Forum',title:t.title,sub:t.author,action:function(id){return function(){CM();go('for');};}(t.id)});});
  (DB.formations||[]).forEach(function(f){if(f.title.toLowerCase().indexOf(q)>=0)results.push({type:'Formation',title:f.title,sub:f.desc||'',action:function(id){return function(){CM();go('form');};}(f.id)});});
  (DB.voteWars||[]).forEach(function(w){if(w.title.toLowerCase().indexOf(q)>=0)results.push({type:'Guerre',title:w.title,sub:w.date,action:function(){CM();go('vote');}});});
  (DB.events||[]).forEach(function(e){if(e.title.toLowerCase().indexOf(q)>=0)results.push({type:'Événement',title:e.title,sub:e.date,action:function(){CM();go('cal');}});});
  if(!results.length){res.innerHTML='<div class="td tsm" style="padding:8px">Aucun résultat pour "'+esc(q)+'"</div>';return;}
  res.innerHTML=results.slice(0,20).map(function(r,i){return'<div onclick="gsActions['+i+']()" class="gs-item" style="padding:10px 14px;border-bottom:1px solid var(--b1);cursor:pointer;display:flex;align-items:center;gap:10px"><div style="font-size:10px;color:var(--tx3);min-width:80px">'+r.type+'</div><div><div style="font-size:13px;font-weight:600;color:var(--tx1)">'+esc(r.title)+'</div>'+(r.sub?'<div style="font-size:10px;color:var(--tx3)">'+esc(r.sub)+'</div>':'')+'</div></div>';}).join('');
  window.gsActions=results.slice(0,20).map(function(r){return r.action;});
}

// ════════════════════════════════════════
// STATISTIQUES
// ════════════════════════════════════════
function pgStats(){
  if(!CU||CU.username.toLowerCase()!=='adminfs') return '<div class="td ta-c" style="padding:60px">⛔ Accès réservé.</div>';
  var wars=(DB.voteWars||[]).filter(function(w){return !w.seasonId;}).slice().sort(function(a,b){return b.date.localeCompare(a.date);});
  if(!wars.length)return'<div class="td ta-c" style="padding:40px">Aucune guerre pour la saison en cours.</div>';
  var members=DB.members.filter(function(m){return m.status!=='recrue';});
  var stats={};
  members.forEach(function(m){
    var present=0,late=0,absent=0,novote=0,total=wars.length;
    wars.forEach(function(w){
      var v=(w.votes||{})[m.id];
      if(!v){ novote++; return; }
      if(v.vote==='present'){
        var warT=(w.date&&w.time)?parseLocalDateTime(w.date,w.time):null;
        var voteT=v.updatedAt?new Date(v.updatedAt).getTime():0;
        if(warT&&voteT>warT) late++;
        else present++;
      } else if(v.vote==='absent'){ absent++; }
      else novote++;
    });
    var rate=total>0?Math.round((present+late)/total*100):0;
    stats[m.id]={present,late,absent,novote,total,rate,m};
  });
  var sorted=Object.values(stats).sort(function(a,b){return b.rate-a.rate;});
  return'<div class="pan" style="margin-bottom:16px"><div class="ph"><span class="ptl">📊 Statistiques de participation</span><span class="td tsm" style="margin-left:auto">'+wars.length+' guerre(s)</span></div><div style="overflow-x:auto"><table style="font-size:12px;width:100%"><thead><tr><th>Joueur</th><th>✅</th><th>⏰</th><th>❌</th><th>⏳</th><th>Présence</th></tr></thead><tbody>'+sorted.map(function(s){var rc=s.rate>=70?'#66bb6a':s.rate>=40?'#f9a825':'var(--red3)';return'<tr><td>'+avaHTML(s.m,20)+' '+esc(s.m.username)+'</td><td style="text-align:center;color:#66bb6a">'+s.present+'</td><td style="text-align:center;color:#f9a825">'+s.late+'</td><td style="text-align:center;color:var(--red3)">'+s.absent+'</td><td style="text-align:center;color:var(--tx3)">'+s.novote+'</td><td><div style="display:flex;align-items:center;gap:6px"><div style="flex:1;height:6px;background:var(--bg1);border-radius:3px"><div style="height:100%;width:'+s.rate+'%;background:'+rc+';border-radius:3px"></div></div><span style="color:'+rc+';font-weight:700;min-width:32px">'+s.rate+'%</span></div></td></tr>';}).join('')+'</tbody></table></div></div>';
}

// ════════════════════════════════════════
// CLASSEMENT
// ════════════════════════════════════════
function pgRank(){
  if(!CU||CU.username.toLowerCase()!=='adminfs') return '<div class="td ta-c" style="padding:60px">⛔ Accès réservé.</div>';
  var wars=(DB.voteWars||[]).filter(function(w){return !w.seasonId;});
  var members=DB.members.filter(function(m){return m.status!=='recrue';});
  var ranked=members.map(function(m){
    var present=0,late=0,absent=0,novote=0,total=wars.length;
    wars.forEach(function(w){
      var v=(w.votes||{})[m.id];
      if(!v){ novote++; return; }
      if(v.vote==='present'){
        var warT=(w.date&&w.time)?parseLocalDateTime(w.date,w.time):null;
        var voteT=v.updatedAt?new Date(v.updatedAt).getTime():0;
        if(warT&&voteT>warT) late++;
        else present++;
      } else if(v.vote==='absent'){ absent++; }
      else novote++;
    });
    // Score : présent=+5, présent en retard=+3, absent=+3, sans vote=-1
    var score = (present*5) + (late*3) + (absent*3) + (novote*-1);
    if(score < 0) score = 0;
    return{m, present, late, absent, novote, total, score};
  }).sort(function(a,b){
    if(b.score !== a.score) return b.score - a.score;
    // Départage : plus de présences
    if(b.present !== a.present) return b.present - a.present;
    // Puis moins de sans-vote
    return a.novote - b.novote;
  });
  var medals=['🥇','🥈','🥉'];
  if(!wars.length) return '<div class="td ta-c" style="padding:40px">Aucune guerre dans l\'historique.</div>';
  return '<div class="pan"><div class="ph"><span class="ptl">🏆 Classement</span><span class="td tsm" style="margin-left:auto">'+wars.length+' guerre(s)</span></div><div>'
    +ranked.map(function(r,i){
      var voted=r.present+r.absent;
      var voteRate=r.total>0?Math.round(voted/r.total*100):0;
      var presenceRate=r.total>0?Math.round(r.present/r.total*100):0;
      var rc=presenceRate>=70?'#66bb6a':presenceRate>=40?'#f9a825':'var(--red3)';
      return '<div style="padding:12px 16px;border-bottom:1px solid var(--b1);display:flex;align-items:center;gap:12px">'
        +'<div style="font-size:'+(i<3?'22px':'14px')+';min-width:36px;text-align:center;font-weight:700;color:var(--gold)">'+(medals[i]||(i+1))+'</div>'
        +avaHTML(r.m,36)
        +'<div style="flex:1;min-width:0">'
          +'<div class="cin fw7" style="font-size:13px">'+esc(r.m.username)+(r.m.chefGroupe?' 🗡️':'')+(r.m.sanguin?' 🩸':'')+(r.m.grandChampion?' 🏆':'')+'</div>'
          +'<div style="display:grid;grid-template-columns:repeat(5,1fr);gap:5px;margin-top:6px">'
            +'<div style="background:var(--bg1);border-radius:2px;padding:4px 6px;text-align:center">'
              +'<div style="font-size:14px;font-weight:700;color:#66bb6a">'+r.present+'</div>'
              +'<div style="font-size:9px;color:var(--tx3)">✅ Présent</div>'
            +'</div>'
            +'<div style="background:var(--bg1);border-radius:2px;padding:4px 6px;text-align:center">'
              +'<div style="font-size:14px;font-weight:700;color:#f9a825">'+r.late+'</div>'
              +'<div style="font-size:9px;color:var(--tx3)">⏰ En retard</div>'
            +'</div>'
            +'<div style="background:var(--bg1);border-radius:2px;padding:4px 6px;text-align:center">'
              +'<div style="font-size:14px;font-weight:700;color:var(--red3)">'+r.absent+'</div>'
              +'<div style="font-size:9px;color:var(--tx3)">❌ Absent</div>'
            +'</div>'
            +'<div style="background:var(--bg1);border-radius:2px;padding:4px 6px;text-align:center">'
              +'<div style="font-size:14px;font-weight:700;color:var(--tx3)">'+r.novote+'</div>'
              +'<div style="font-size:9px;color:var(--tx3)">⏳ Sans vote</div>'
            +'</div>'
          +'</div>'
        +'</div>'
        +'<div style="font-size:14px;font-weight:700;color:var(--gold);text-align:right;min-width:40px">'+r.score+'<div style="font-size:9px;color:var(--tx3)">pts</div></div>'
      +'</div>';
    }).join('')
  +'</div></div>'
  +'<div style="font-size:10px;color:var(--tx3);margin-top:8px;padding:10px 14px;background:var(--bg2);border-radius:3px;line-height:1.8">'
  +'Score basé uniquement sur la participation aux guerres territoriales<br>'
  +'✅ Présent = +5 pts &nbsp;·&nbsp; ⏰ En retard = +3 pts &nbsp;·&nbsp; ❌ Absent = +3 pts &nbsp;·&nbsp; ⏳ Sans vote = −1 pt'
  +'</div>';
}

