      +'<td style="padding:5px 8px;font-weight:600">'+esc(m.username)+(m.sanguin?' 🩸':'')+(m.chefGroupe?' 🗡️':'')+(m.grandChampion?' 🏆':'')+'</td>'
      +'<td style="padding:5px 8px;font-size:10px;color:'+statusColor+'">'+esc(m.status)+'</td>'
