function getBadgeState(){try{return JSON.parse(sessionStorage.getItem('badge_state')||'{}');}catch(e){return{};}}
function setBadgeState(key,val){var s=getBadgeState();s[key]=val;try{sessionStorage.setItem('badge_state',JSON.stringify(s));}catch(e){}}
function threadHasUnread(t){
  if(!CU) return false;
  var reads=DB.threadReads||{};
  var readAt=reads[t.id]||'';
  // Thread jamais lu et pas créé par moi
  if(!readAt) return t.author!==CU.username;
  // Vérifier si une réponse d'un autre est plus récente que ma dernière lecture
  return (t.replies||[]).some(function(r){
    return r.author!==CU.username && r.date && r.date>readAt;
  });
}

function markThreadRead(threadId){
  if(!CU||!threadId) return;
  DB.threadReads=DB.threadReads||{};
  var now=new Date().toISOString();
  DB.threadReads[threadId]=now;
  fetch(SB_URL+'/rest/v1/thread_reads',{
    method:'POST',
    headers:Object.assign({},SB._headers,{'Prefer':'resolution=merge-duplicates,return=minimal'}),
    body:JSON.stringify([{membre_id:CU.id,thread_id:threadId,read_at:now}])
  }).catch(function(e){console.warn('[threadRead]',e);});
  updateAppBadge();
}
function markSeen(section){
  var now=new Date().getTime();
  if(section==='forum')setBadgeState('last_forum',new Date().toISOString().substring(0,10));
  if(section==='form')setBadgeState('last_form',new Date().toISOString().substring(0,10));
  if(section==='vote')setBadgeState('last_vote',now);
  if(section==='grp')setBadgeState('last_grp',now);
  if(section==='cal')setBadgeState('last_cal',now);
  if(section==='banner')setBadgeState('last_banner',now);
  updateAppBadge();
}
function updateAppBadge(){
  if(!CU)return;
  var count=0,state=getBadgeState(),badges={home:0,vote:0,grp:0,for:0,form:0,cal:0,rec:0};
  if(typeof canApproveRec==='function'&&canApproveRec()){badges.rec=(DB.pendingMembers||[]).filter(function(p){return p.status==='attente';}).length;count+=badges.rec;}
  var lastBanner=state['last_banner']||0;
  badges.home+=(DB.banners||[]).filter(function(b){return b.active&&b.createdAt&&new Date(b.createdAt).getTime()>lastBanner;}).length;
  (DB.voteWars||[]).filter(function(w){return w.status==='open';}).forEach(function(w){if(!(w.votes&&w.votes[CU.id]))badges.vote++;});
  count+=badges.vote;
  badges.for=(DB.forumThreads||[]).filter(function(t){
    if(!TAG_LBL||Object.keys(TAG_LBL).indexOf(t.tag)<0) return false;
    return threadHasUnread(t);
  }).length;
  count+=badges.for;
  badges.form=(DB.forumThreads||[]).filter(function(t){
    if(!TAG_LBL_FORM||Object.keys(TAG_LBL_FORM).indexOf(t.tag)<0) return false;
    return threadHasUnread(t);
  }).length;
  count+=badges.form;
  var lastCal=state['last_cal']||0;
  badges.cal=(DB.events||[]).filter(function(e){return e.createdAt&&new Date(e.createdAt).getTime()>lastCal;}).length;
  count+=badges.cal;
  if('setAppBadge' in navigator){if(count>0)navigator.setAppBadge(count).catch(function(){});else navigator.clearAppBadge().catch(function(){});}
  updateSidebarBadges(badges);
}
function updateSidebarBadges(badges){
  var map={'badge-forum':badges.for||0,'badge-form':badges.form||0,'badge-vote':badges.vote||0,'badge-grp':badges.grp||0,'badge-cal':badges.cal||0,'badge-home':badges.home||0,'br':badges.rec||0};
  Object.entries(map).forEach(function(e){var el=document.getElementById(e[0]);if(el){el.textContent=e[1];el.style.display=e[1]>0?'inline':'none';}});
}
function addNavBadge(navId,badgeId){var ni=document.getElementById(navId);if(ni&&!document.getElementById(badgeId)){var b=document.createElement('span');b.id=badgeId;b.className='nav-badge';b.style.display='none';ni.appendChild(b);}}
