function showImg(el){openImgFull(el.dataset.img);}
function openImgFull(src){
  var overlay=document.createElement('div');
  overlay.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.9);z-index:9999;display:flex;align-items:center;justify-content:center;cursor:zoom-out';
  overlay.onclick=function(){document.body.removeChild(overlay);};
  var img=document.createElement('img');
  img.src=src;
  img.style.cssText='max-width:95vw;max-height:95vh;border-radius:4px;object-fit:contain';
  overlay.appendChild(img);
  document.body.appendChild(overlay);
}

