function OM(title,body,btns){
  document.getElementById('mtit').textContent=title;
  document.getElementById('mbdy').innerHTML=body;
  document.getElementById('mft').innerHTML=(btns||[]).map(function(b,i){
    return'<button class="btn '+b.cls+'" id="mb'+i+'">'+b.lbl+'</button>';
  }).join('');
  (btns||[]).forEach(function(b,i){document.getElementById('mb'+i).onclick=b.fn;});
  document.getElementById('mo').classList.add('open');
}
function CM(){document.getElementById('mo').classList.remove('open');}
document.getElementById('mo').onclick=function(e){if(e.target===this)CM();};

