// ════════════════════════════════════════════════════════════════
// CALCUL AUTOMATIQUE DES STATUTS
// ════════════════════════════════════════════════════════════════
// Retourne true si un membre doit être surveillé (cumul d'indicateurs RH)
// Conditions : sanction active OU inactif OU risque inactif OU unités inchangées
function needsWatch(m){
  if(m.role==='recrue') return false;
  var activeSanctions=(m.sanctions||[]).filter(function(s){return !s.type||s.type.indexOf('✅')<0;}).length;
  if(activeSanctions>0) return true;
  if(m.status==='inactif') return true;
  if(m.status==='actif'&&computeMemberStatus(m)==='inactif') return true;
  if(isUnitStale(m)) return true;
  return false;
}

// Retourne true si le vote compte comme une participation (présent ou retard)
function isParticipation(vote){
  return vote&&(vote.vote==='present'||vote.vote==='retard'||vote.vote==='late');
}

// Calcule le statut d'activité d'un membre selon les nouvelles règles :
// INACTIF : 3 absences/novote consécutives
// ACTIF   : au moins 1 participation dans chacune des 3 tranches de 3 guerres (sur les 9 dernières)
// Recrues : ignorées (appelant doit vérifier)
function computeMemberStatus(m){
  var closedWars=(DB.voteWars||[])
    .filter(function(w){return w.status==='closed'&&!w.seasonId;})
    .sort(function(a,b){return b.date.localeCompare(a.date);});

  // Pas assez d'historique — ne rien changer
  if(closedWars.length<3) return m.status;

  // ── Règle INACTIF : 3 non-participations consécutives ──────────
  var consecutive=0;
  for(var i=0;i<closedWars.length;i++){
    var v=(closedWars[i].votes||{})[m.id];
    if(!isParticipation(v)) consecutive++;
    else break;
    if(consecutive>=3) return 'inactif';
  }

  // ── Règle ACTIF : 1 participation par tranche de 3 sur 9 ──────
  var last9=closedWars.slice(0,9);
  // Si moins de 9 guerres, on calcule sur les tranches complètes disponibles
  var nbTranches=Math.floor(last9.length/3);
  if(nbTranches<1) return m.status;

  var allTranchesOK=true;
  for(var t=0;t<nbTranches;t++){
    var tranche=last9.slice(t*3,(t+1)*3);
    var hasOne=tranche.some(function(w){
      return isParticipation((w.votes||{})[m.id]);
    });
    if(!hasOne){allTranchesOK=false;break;}
  }
  if(allTranchesOK) return 'actif';

  return m.status; // Conserver si aucune règle ne s'applique clairement
}

// Retourne le détail d'activité d'un membre pour le rapport RH
// { wars: [{date, title, participated}], tranches: [{ok, wars}], consecutive: N, status: 'actif'|'inactif' }
function getMemberActivityReport(m){
  var closedWars=(DB.voteWars||[])
    .filter(function(w){return w.status==='closed'&&!w.seasonId;})
    .sort(function(a,b){return b.date.localeCompare(a.date);})
    .slice(0,9);

  var wars=closedWars.map(function(w){
    var v=(w.votes||{})[m.id];
    var participated=isParticipation(v);
    var label=!v?'—':v.vote==='absent'?'Absent':'Présent';
    return{date:w.date,title:w.title,participated:participated,label:label};
  });

  var consecutive=0;
  for(var i=0;i<wars.length;i++){
    if(!wars[i].participated) consecutive++;
    else break;
  }

  var tranches=[];
  var nbT=Math.floor(wars.length/3);
  for(var t=0;t<nbT;t++){
    var tr=wars.slice(t*3,(t+1)*3);
    var ok=tr.some(function(x){return x.participated;});
    tranches.push({ok:ok,wars:tr});
  }

  var computedStatus=computeMemberStatus(m);
  return{wars:wars,tranches:tranches,consecutive:consecutive,computedStatus:computedStatus,total:closedWars.length};
}

// Mise à jour silencieuse des statuts — appelée automatiquement à la clôture d'une guerre
function silentUpdateStatuses(){
  // Pas assez de guerres clôturées cette saison — ne rien changer
  var closedWars=(DB.voteWars||[]).filter(function(w){return w.status==='closed'&&!w.seasonId;});
  if(closedWars.length<3) return;
  DB.members.forEach(function(m){
    if(m.role==='recrue') return;
    var newStatus=computeMemberStatus(m);
    if(newStatus!==m.status){
      m.status=newStatus;
      sbSaveMember(m).catch(function(e){console.warn('[silentStatus]',e);});
    }
  });
}

function autoUpdateStatuses(){
  if(!HR('officier')) return;
  var changed=[];
  DB.members.forEach(function(m){
    if(m.role==='recrue') return; // Ne pas changer les recrues
    var newStatus=computeMemberStatus(m);
    if(newStatus!==m.status){
      changed.push({username:m.username, old:m.status, new:newStatus});
      m.status=newStatus;
      sbSaveMember(m);
    }
  });
  if(changed.length){
    alert('Statuts mis à jour:\n'+changed.map(function(c){return c.username+': '+c.old+' \u2192 '+c.new}).join('\n'));
    sbLoad().then(function(){go('mbr');});
  } else {
    alert('Tous les statuts sont à jour.');
  }
}

// Répare les votes enregistrés sous un ancien ID 'p...' après approbation
// À lancer une seule fois si des membres ont été approuvés avec l'ancien code
function migrateVoteKeys(){
  if(!HR('admin')) return;
  // Construire un map username -> id actuel
  var usernameToId={};
  DB.members.forEach(function(m){ usernameToId[m.username.toLowerCase()]=m.id; });
  var fixes=0;
  (DB.voteWars||[]).forEach(function(w){
    var votes=w.votes||{};
    var newVotes={};
    var changed=false;
    Object.keys(votes).forEach(function(key){
      // Si la clé commence par 'p' et qu'aucun membre actuel n'a cet ID
      var member=DB.members.find(function(m){return m.id===key;});
      if(!member){
        // Tenter de trouver le membre par son vote (on ne peut pas deviner le username ici)
        newVotes[key]=votes[key]; // conserver la clé orpheline
      } else {
        newVotes[key]=votes[key];
      }
    });
    if(changed){ w.votes=newVotes; sbSaveWar(w); fixes++; }
  });
  alert('Migration terminée. '+fixes+' guerre(s) corrigée(s). Rechargement...');
  sbLoad().then(function(){go('mbr');});
}

function pgMbr(){
  if(HR('officier'))document.getElementById('tact').innerHTML=
    '<button class="btn bg bsm" onclick="openAddMbr()">+ Ajouter</button>'
    +'<button class="btn bol bsm" style="margin-left:6px" onclick="autoUpdateStatuses()">↺ Statuts auto</button>';

  var members=DB.members.slice().sort(function(a,b){return a.username.localeCompare(b.username);});
  if(!members.length) return'<div class="td ta-c" style="padding:40px">Aucun membre.</div>';

  var activeFilter=window._mbrFilter||'tous';
  var activeSearch=window._mbrSearch||'';
  var compact=window._mbrCompact!==false;

  var filters=[
    {k:'tous',   label:'Tous ('+members.length+')'},
    {k:'actif',  label:'✅ Actifs'},
    {k:'inactif',label:'⏸ Inactifs'},
    {k:'sanguin',label:'🩸 Gardes'},
    {k:'champion',label:'🏆 Champions'},
    {k:'chef',   label:'🗡️ Chefs'}
  ];

  var filterBar='<div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:12px">'
    +filters.map(function(f){
      return'<button onclick="setMbrFilter(this)" data-f="'+f.k+'" class="btn '+(activeFilter===f.k?'bg':'bol')+' bsm" style="font-size:10px">'+f.label+'</button>';
    }).join('')+'</div>';

  var searchBar='<div style="margin-bottom:12px">'
    +'<input class="fi" id="mbr-search" placeholder="🔍 Rechercher un membre..." value="'+esc(activeSearch)+'"'
    +' oninput="setMbrSearch(this.value)" style="font-size:13px"></div>';

  var filtered=members.filter(function(m){
    if(activeSearch&&m.username.toLowerCase().indexOf(activeSearch.toLowerCase())<0) return false;
    if(activeFilter==='actif')    return m.status==='actif';
    if(activeFilter==='inactif')  return m.status==='inactif';
    if(activeFilter==='sanguin')  return m.sanguin;
    if(activeFilter==='champion') return m.grandChampion;
    if(activeFilter==='chef')     return m.chefGroupe;
    return true;
  });

  var toggleBtn='<button onclick="setMbrCompact('+(!compact)+')" class="btn bol bsm" style="font-size:10px">'+(compact?'☰ Détails':'⊟ Compact')+'</button>';

  var html='<div class="pan"><div class="ph"><span class="ptl">Combattants de la Maison</span>'
    +'<span style="font-size:11px;color:var(--tx3);margin-left:8px">'+filtered.length+'/'+members.length+'</span>'
    +toggleBtn+'</div>'
    +'<div class="pb">'+filterBar+searchBar+'</div><div>';

  if(!filtered.length){
    html+='<div class="td ta-c" style="padding:24px;color:var(--tx3)">Aucun membre correspondant.</div>';
  } else if(compact){
    html+=filtered.map(function(m){
      var isMe=m.id===CU.id;
      var sanctions=(m.sanctions||[]).filter(function(s){return s.type&&s.type.indexOf('✅')<0;}).length;
      return'<div style="padding:7px 16px;border-bottom:1px solid var(--b1);cursor:pointer;display:flex;align-items:center;gap:10px;'+(isMe?'background:rgba(201,162,39,.05)':'')+'"'
        +' onclick="openMbrProfileW(this)" data-id="'+m.id+'">'
        +avaHTML(m,28)
        +'<div style="flex:1;min-width:0;display:flex;align-items:center;gap:6px;flex-wrap:wrap">'
        +'<span style="font-size:13px;font-weight:700;color:'+(isMe?'var(--gold)':'var(--tx1)')+'">'+esc(m.username)+(m.chefGroupe?' 🗡️':'')+(m.sanguin?' 🩸':'')+(m.grandChampion?' 🏆':'')+(m.isGuest?' <span style="font-size:9px;background:rgba(201,162,39,.15);color:var(--gold);padding:1px 5px;border-radius:8px;border:1px solid rgba(201,162,39,.3)">🎟️ Invité</span>':'')+(isUnitStale(m)&&(HR('recrutement')||HR('officier')||isGDoc())?'<span style="font-size:8px;background:rgba(249,168,37,.15);color:#f9a825;padding:1px 5px;border-radius:8px;border:1px solid rgba(249,168,37,.4);margin-left:4px">⚠️ Unités inchangées</span>':'')+'</span>'
        +'<span class="badge '+(m.status==='actif'?'bok':'bof')+'" style="font-size:9px">'+esc(m.status)+'</span>'
        +rb(m)
        +(sanctions>0&&HR('officier')?'<span class="badge bred" style="font-size:9px">⚠️</span>':'')
        +(isRH()&&needsWatch(m)?'<span style="font-size:9px;background:rgba(139,26,10,.3);color:#ff6b6b;padding:1px 5px;border-radius:8px;border:1px solid #8b0000;font-weight:700">🔴 Surveiller</span>':'')
        +'</div>'
        +'<div style="display:flex;gap:4px;flex-shrink:0">'
        +(HR('officier')?'<button class="btn bol bsm" onclick="editMbrW(this);event.stopPropagation()" data-id="'+m.id+'" style="font-size:10px">✏️</button>':'')
        +(HR('officier')&&m.id!==CU.id?'<button class="btn bred bsm" onclick="delMbrW(this);event.stopPropagation()" data-id="'+m.id+'" style="font-size:10px">✕</button>':'')
        +'<span style="font-size:12px;color:var(--tx3)">›</span>'
        +'</div>'
        +'</div>';
    }).join('');
  } else {
    html+=filtered.map(function(m){
      var isMe=m.id===CU.id;
      var sanctions=(m.sanctions||[]).filter(function(s){return s.type&&s.type.indexOf('✅')<0;}).length;
      var maxMastery=(m.units||[]).reduce(function(a,u){return Math.max(a,u.mastery||0);},0);
      return'<div style="padding:12px 16px;border-bottom:1px solid var(--b1);cursor:pointer;'+(isMe?'background:rgba(201,162,39,.05)':'')+'"'
        +' onclick="openMbrProfileW(this)" data-id="'+m.id+'">'
        +'<div style="display:flex;align-items:center;gap:10px">'
        +avaHTML(m,38)
        +'<div style="flex:1;min-width:0">'
        +'<div style="font-size:14px;font-weight:700;color:'+(isMe?'var(--gold)':'var(--tx1)')+'">'+esc(m.username)+(m.chefGroupe?' 🗡️':'')+(m.sanguin?' 🩸':'')+(m.grandChampion?' 🏆':'')+(m.isGuest?' <span style="font-size:9px;background:rgba(201,162,39,.15);color:var(--gold);padding:1px 5px;border-radius:8px;border:1px solid rgba(201,162,39,.3)">🎟️ Invité</span>':'')+(isUnitStale(m)&&(HR('recrutement')||HR('officier')||isGDoc())?'<span style="font-size:8px;background:rgba(249,168,37,.15);color:#f9a825;padding:1px 5px;border-radius:8px;border:1px solid rgba(249,168,37,.4);margin-left:4px">⚠️ Unités inchangées</span>':'')+'</div>'
        +'<div style="display:flex;flex-wrap:wrap;gap:4px;margin-top:3px">'+rb(m)
        +'<span class="badge '+(m.status==='actif'?'bok':'bof')+'">'+esc(m.status)+'</span>'
        +(sanctions>0&&HR('officier')?'<span class="badge bred" style="font-size:9px">⚠️ '+sanctions+'</span>':'')
        +(m.status==='actif'&&computeMemberStatus(m)==='inactif'?'<span class="badge bof" style="font-size:9px">⚠️ Risque inactif</span>':'')
        +(isRH()&&needsWatch(m)?'<span style="font-size:9px;background:rgba(139,26,10,.3);color:#ff6b6b;padding:1px 5px;border-radius:8px;border:1px solid #8b0000;font-weight:700">🔴 Surveiller</span>':'')
        +'</div>'
        +(m.classes&&m.classes.length?'<div style="display:flex;flex-wrap:wrap;gap:3px;margin-top:4px">'+memberClassBadges(m)+'</div>':'')
        +'<div style="font-size:10px;color:var(--tx3);margin-top:4px">🛡️ '+(m.units&&m.units.length?m.units.length+' unité(s) · max '+maxMastery+'★':'Aucune unité')+'</div>'
        +'</div>'
        +'<div style="display:flex;gap:6px;flex-shrink:0;align-items:center">'
        +(HR('officier')?'<button class="btn bol bsm" onclick="editMbrW(this);event.stopPropagation()" data-id="'+m.id+'">✏️</button>':'')
        +(HR('officier')&&m.id!==CU.id?'<button class="btn bred bsm" onclick="delMbrW(this);event.stopPropagation()" data-id="'+m.id+'">✕</button>':'')
        +'<span style="font-size:12px;color:var(--tx3)">›</span>'
        +'</div>'
        +'</div>'
        +'</div>';
    }).join('');
  }
  html+='</div></div>';
  return html;
}

function setMbrCompact(v){ window._mbrCompact=v; var el=document.getElementById('content'); if(el){var s=el.scrollTop;el.innerHTML=pgMbr();el.scrollTop=s;} }

function setMbrFilter(btn){ window._mbrFilter=btn.dataset.f; var el=document.getElementById('content'); if(el){var s=el.scrollTop;el.innerHTML=pgMbr();el.scrollTop=s;} }
function setMbrSearch(v){ window._mbrSearch=v; var el=document.getElementById('content'); if(el){var s=el.scrollTop;el.innerHTML=pgMbr();el.scrollTop=s;} }
function openMbrProfileW(el){ openMbrProfile(el.dataset.id); }

function setMbrUnitMastery(memberId, unitIdx, val){
  unitIdx=parseInt(unitIdx); val=parseInt(val);
  var m=DB.members.find(function(x){return x.id===memberId;});
  if(!m||!m.units[unitIdx]) return;
  m.units[unitIdx].mastery=val;
  m.unitsUpdatedAt=new Date().toISOString();
  sbSaveMember(m).then(function(){openMbrProfile(memberId);}).catch(function(e){console.warn(e);});
}

function openMbrProfile(id){
  var m=DB.members.find(function(x){return x.id===id;});
  if(!m) return;
  var wars=DB.voteWars||[];
  var present=0,absent=0,novote=0;
  wars.forEach(function(w){
    var v=(w.votes||{})[m.id];
    if(!v) novote++;
    else if(v.vote==='present') present++;
    else absent++;
  });
  var total=wars.length;
  var presRate=total?Math.round(present/total*100):0;
  var rc=presRate>=70?'#66bb6a':presRate>=40?'#f9a825':'var(--red3)';
  var html='';
  html+='<div style="text-align:center;padding:12px 0 18px">';
  html+=avaHTML(m,64);
  html+='<div style="font-family:Cinzel,serif;font-size:18px;font-weight:700;color:var(--tx1);margin-top:10px">'+esc(m.username)+'</div>';
  html+='<div style="display:flex;justify-content:center;gap:6px;margin-top:6px;flex-wrap:wrap">';
  html+=rb(m);
  html+='<span class="badge '+(m.status==='actif'?'bok':'bof')+'">'+esc(m.status)+'</span>';
  if(m.chefGroupe)    html+='<span class="badge" style="background:rgba(112,144,168,.2);color:var(--teal2)">🗡️ Chef de Groupe</span>';
  if(m.sanguin)       html+='<span class="badge" style="background:rgba(139,26,10,.2);color:var(--red3)">🩸 Garde Sanguin</span>';
  if(m.grandChampion) html+='<span class="badge" style="background:rgba(201,162,39,.15);color:var(--gold)">🏆 Grand Champion</span>';
  (m.extraRoles||[]).forEach(function(r){html+='<span class="badge '+(cls[r]||'bmb')+'" style="font-size:9px">'+esc(RN[r]||r)+'</span>';});
  html+='</div>';
  if(m.joinDate) html+='<div style="font-size:11px;color:var(--tx3);margin-top:6px">Membre depuis '+fmtDate(m.joinDate.slice(0,10))+'</div>';
  if(m.playerLevel||m.influenceLevel){
    html+='<div style="display:flex;justify-content:center;gap:12px;margin-top:8px">';
    if(m.playerLevel) html+='<div style="background:var(--bg1);border:1px solid var(--golddim);border-radius:3px;padding:4px 12px;font-size:11px;color:var(--gold)">⚔️ Niveau joueur : <strong>'+m.playerLevel+'</strong></div>';
    if(m.influenceLevel) html+='<div style="background:var(--bg1);border:1px solid rgba(100,181,246,.4);border-radius:3px;padding:4px 12px;font-size:11px;color:#64b5f6">👑 Influence : <strong>'+m.influenceLevel+'</strong></div>';
    html+='</div>';
  }
  html+='</div>';

  if(m.classes&&m.classes.length){
    html+='<div style="margin-bottom:14px"><div style="font-size:10px;font-weight:700;color:var(--tx3);letter-spacing:1px;margin-bottom:6px">CLASSES</div>';
    html+='<div style="display:flex;flex-wrap:wrap;gap:4px">'+memberClassBadges(m)+'</div></div>';
  }
  if(m.units&&m.units.length){
    var canEditStars=(HR('officier')||isGDoc())&&m.id!==CU.id;
    html+='<div style="margin-bottom:14px">';
    html+='<div style="display:flex;align-items:center;margin-bottom:6px">';
    html+='<div style="font-size:10px;font-weight:700;color:var(--tx3);letter-spacing:1px">UNITÉS ('+m.units.length+')</div>';
    if(isUnitStale(m)&&(HR('recrutement')||HR('officier')||isGDoc())) html+='<span style="font-size:8px;background:rgba(249,168,37,.15);color:#f9a825;padding:1px 5px;border-radius:8px;border:1px solid rgba(249,168,37,.4);margin-left:8px">⚠️ Unités inchangées</span>';
    html+='</div>';
    html+='<div style="display:flex;flex-wrap:wrap;gap:6px">';
    m.units.forEach(function(u,ui){
      var rs=unitRarityStyle(u.name);
      var isMeta=(DB.metaUnits||[]).indexOf(u.name)>=0;
      if(canEditStars){
        html+='<div style="background:'+rs.bg+';border:1px solid '+rs.border+';border-radius:3px;padding:4px 8px;font-size:10px">';
        html+='<div style="color:'+rs.color+';margin-bottom:3px">'+esc(u.name)+(isMeta?'<span style="font-size:7px;background:var(--gold);color:#000;padding:1px 3px;border-radius:2px;margin-left:3px">META</span>':'')+'</div>';
        html+='<div style="display:flex;gap:1px">';
        for(var n=1;n<=5;n++){
          html+='<span style="font-size:13px;cursor:pointer;color:'+(u.mastery>=n?'var(--gold)':'var(--tx3)')+'" onclick="setMbrUnitMastery(this.dataset.mid,this.dataset.ui,this.dataset.n)" data-mid="'+m.id+'" data-ui="'+ui+'" data-n="'+n+'">'+(u.mastery>=n?'★':'☆')+'</span>';
        }
        html+='</div></div>';
      } else {
        html+='<span style="background:'+rs.bg+';border:1px solid '+rs.border+';color:'+rs.color+';font-size:10px;padding:2px 8px;border-radius:3px">'+esc(u.name)+' '+'★'.repeat(u.mastery||1)+(isMeta?'<span style="font-size:7px;background:var(--gold);color:#000;padding:1px 3px;border-radius:2px;margin-left:3px">META</span>':'')+'</span>';
      }
    });
    html+='</div></div>';
  }
  if(m.note) html+='<div style="background:var(--bg1);border-radius:3px;padding:10px;font-size:12px;color:var(--tx2);font-style:italic">'+esc(m.note)+'</div>';
  var btns=[{lbl:'Fermer',cls:'bol',fn:CM}];
  if(HR('officier')) btns.unshift({lbl:'✏️ Modifier',cls:'btn bg',fn:function(){CM();editMbr(id);}});
  if(isGDoc()&&!HR('officier')) btns.unshift({lbl:'📝 Note',cls:'btn bol',fn:function(){
    OM('Note — '+esc(m.username),
      '<div class="fg"><label class="fl">Commentaire</label><textarea class="ft" id="gdoc-note" style="min-height:80px">'+esc(m.note||'')+'</textarea></div>',
      [{lbl:'Annuler',cls:'bol',fn:function(){CM();openMbrProfile(id);}},
       {lbl:'💾 Sauvegarder',cls:'btn bg',fn:function(){
         m.note=gVal('gdoc-note');
         sbSaveMember(m).then(function(){CM();openMbrProfile(id);}).catch(function(e){console.warn(e);});
       }}]);
  }});
  if(isGDoc()&&!HR('officier')&&(m.role==='recrue'||m.role==='membre')){
    var toRole=m.role==='recrue'?'membre':'recrue';
    var toLbl=m.role==='recrue'?'✅ Passer Membre':'↩️ Repasser Recrue';
    btns.unshift({lbl:toLbl,cls:'btn '+(m.role==='recrue'?'bg':'bol'),fn:function(){
      if(!confirm('Passer '+m.username+' en '+toRole+' ?')) return;
      CM();
      fetch('/.netlify/functions/update-role',{method:'POST',headers:{'Content-Type':'application/json','x-foedus-key':FOEDUS_PUSH_SECRET},body:JSON.stringify({callerId:CU.id,targetId:m.id,newRole:toRole})})
        .then(function(r){return r.json();})
        .then(function(d){if(d.success){m.role=toRole;go('mbr');}else alert('Erreur: '+d.error);})
        .catch(function(e){console.warn(e);});
    }});
  }
  OM(esc(m.username),html,btns);
}

function openAddMbr(){
  OM('Ajouter un membre',
    '<div class="fr2"><div class="fg"><label class="fl">Pseudo</label><input class="fi" id="am-u"></div><div class="fg"><label class="fl">PIN</label><input class="fi" type="password" id="am-p"></div></div>'
    +'<div class="fr2"><div class="fg"><label class="fl">Rôle</label><select class="fs" id="am-r">'+(HR('admin')?Object.entries(RN):Object.entries(RN).filter(function(e){return e[0]!=='admin';})).map(function(e){return'<option value="'+e[0]+'">'+e[1]+'</option>';}).join('')+'</select></div>'
    +'<div class="fg"><label class="fl">Statut</label><select class="fs" id="am-s"><option value="actif">Actif</option><option value="inactif">Inactif</option></select></div></div>'
    +'<div class="fg"><label class="fl" style="display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" id="am-sg"> Garde Sanguin 🩸</label></div>'+'<div class="fg"><label class="fl" style="display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" id="am-cg"> Chef de Groupe 🗡️</label></div>'+'<div class="fg"><label class="fl" style="display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" id="am-gc"> Grand Champion 🏆</label></div>'
    +'<div class="fg"><label class="fl">Note</label><input class="fi" id="am-n"></div>',
    [{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'Ajouter',cls:'btn bg',fn:function(){
      var u=sanitize(gVal('am-u'),50),p=gVal('am-p');
      if(!u||!p)return alert('Pseudo et PIN requis');
      sha256(p).then(function(hash){
        var m={id:'m'+Date.now(),username:u,pin:hash,role:gVal('am-r'),status:gVal('am-s'),sanguin:gChk('am-sg'),chefGroupe:gChk('am-cg'),grandChampion:false,joinDate:nowDate(),note:gVal('am-n'),units:[],avatar:''};
        DB.members.push(m);sbSaveMember(m);CM();go('mbr');
      });
    }}]);
}
function editMbr(id){
  var m=gM(id);if(!m)return;
  var myRole=_HR_ROLE||CU.role;

  // Bloquer modification d'un admin par non-admin_assistant/admin
  if(m.role==='admin'&&myRole!=='admin'&&myRole!=='admin_assistant'){
    return alert('Seul un Admin Assistant ou Admin peut modifier le profil d\'un Admin.');
  }
  // Bloquer modification d'un admin_assistant par baron et en dessous
  if(m.role==='admin_assistant'&&myRole!=='admin'&&myRole!=='admin_assistant'){
    return alert('Seul un Admin Assistant ou Admin peut modifier le profil d\'un Admin Assistant.');
  }

  // Filtrer les rôles disponibles selon le rôle de l'éditeur
  var allowedRoles = Object.entries(RN).filter(function(e){
    var rk = e[0];
    // admin : seul admin peut l'attribuer
    if(rk==='admin') return myRole==='admin';
    // admin_assistant : admin, admin_assistant ou baron peuvent l'attribuer
    if(rk==='admin_assistant') return myRole==='admin'||myRole==='admin_assistant'||myRole==='baron';
    return true;
  });

  OM('Modifier le membre',
    '<div class="fg"><label class="fl">Pseudo</label><input class="fi" id="em-u" value="'+esc(m.username)+'"></div>'
    +'<div class="fr2"><div class="fg"><label class="fl">Rôle</label><select class="fs" id="em-r">'+allowedRoles.map(function(e){return'<option value="'+e[0]+'"'+(m.role===e[0]?' selected':'')+'>'+e[1]+'</option>';}).join('')+'</select></div>'
    +'<div class="fg"><label class="fl">Statut</label><select class="fs" id="em-s"><option value="actif"'+(m.status==='actif'?' selected':'')+'>Actif</option><option value="inactif"'+(m.status==='inactif'?' selected':'')+'>Inactif</option></select></div></div>'
    +'<div class="fg"><label class="fl" style="display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" id="em-sg"'+(m.sanguin?' checked':'')+'>Garde Sanguin 🩸</label></div>'+'<div class="fg"><label class="fl" style="display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" id="em-cg"'+(m.chefGroupe?' checked':'')+'>Chef de Groupe 🗡️</label></div>'+'<div class="fg"><label class="fl" style="display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" id="em-gc"'+(m.grandChampion?' checked':'')+'>Grand Champion 🏆</label></div>'
    +'<div class="fg"><label class="fl" style="font-size:10px;font-weight:700;color:var(--tx3);letter-spacing:1px">RÔLES SUPPLÉMENTAIRES</label>'
    +'<div style="display:flex;flex-wrap:wrap;gap:8px;margin-top:4px">'
    +(function(){
      var er=m.extraRoles||[];
      return '<label style="display:flex;align-items:center;gap:5px;cursor:pointer;font-size:12px"><input type="checkbox" id="em-ex-evenement"'+(er.indexOf('evenement')>=0?' checked':'')+'>Resp. Événements</label>'
        +'<label style="display:flex;align-items:center;gap:5px;cursor:pointer;font-size:12px"><input type="checkbox" id="em-ex-recrutement"'+(er.indexOf('recrutement')>=0?' checked':'')+'>Resp. Recrutement</label>'
        +'<label style="display:flex;align-items:center;gap:5px;cursor:pointer;font-size:12px"><input type="checkbox" id="em-ex-formation"'+(er.indexOf('formation')>=0?' checked':'')+'>Resp. Formation</label>'
        +'<label style="display:flex;align-items:center;gap:5px;cursor:pointer;font-size:12px"><input type="checkbox" id="em-ex-responsable_gdoc"'+(er.indexOf('responsable_gdoc')>=0?' checked':'')+'>Resp. GDoc</label>';
    })()
    +'</div></div>'
    +'<div class="fg"><label class="fl">Note</label><input class="fi" id="em-n" value="'+esc(m.note||'')+'"></div>'
    +'<div class="fg"><label class="fl">Nouveau PIN (vide = inchangé)</label><input class="fi" type="password" id="em-p"></div>',
    [{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'Sauvegarder',cls:'btn bg',fn:function(){
      var newRole=gVal('em-r');
      // Vérif finale côté client : officier ne peut pas attribuer admin ou admin_assistant
      if((newRole==='admin'&&myRole!=='admin')||(newRole==='admin_assistant'&&myRole!=='admin'&&myRole!=='admin_assistant'&&myRole!=='baron')){
        return alert('Vous n\'avez pas les droits pour attribuer ce rôle.');
      }
      var oldRole = m.role;
      m.username=sanitize(gVal('em-u'),50)||m.username;
      m.role=newRole;m.status=gVal('em-s');
      m.sanguin=gChk('em-sg');m.chefGroupe=gChk('em-cg');m.grandChampion=gChk('em-gc');m.note=gVal('em-n');
      var extras=[];
      ['evenement','recrutement','formation','responsable_gdoc'].forEach(function(r){
        if(gChk('em-ex-'+r)) extras.push(r);
      });
      m.extraRoles=extras;
      var np=gVal('em-p');
      function save(){
        if(m.id===CU.id)CU=m;
        var idx=DB.members.findIndex(function(x){return x.id===m.id;});
        if(idx>=0)DB.members[idx]=m;
        CM();go('mbr');
        // Si le rôle a changé — passer par la Netlify Function sécurisée
        if(m.role !== oldRole){
          fetch('/.netlify/functions/update-role', {
            method: 'POST',
            headers: {'Content-Type':'application/json','x-foedus-key':FOEDUS_PUSH_SECRET},
            body: JSON.stringify({callerId:CU.id, targetId:m.id, newRole:m.role})
          }).then(function(r){
            if(!r.ok) return r.json().then(function(e){console.warn('[update-role]',e.error);});
            sbAuditLog('role_change', m.id, m.username, (RN[oldRole]||oldRole)+' → '+(RN[m.role]||m.role));
          }).catch(function(e){console.warn('[update-role]',e);});
          // Sauvegarder le reste sans le rôle (géré par update-role)
          var mCopy = Object.assign({}, m, {role: oldRole});
          sbSaveMember(mCopy).catch(function(e){console.warn('[editMbr]',e);});
        } else {
          sbSaveMember(m).catch(function(e){console.warn('[editMbr]',e);});
        }
      }
      if(np){sha256(np).then(function(h){m.pin=h;save();});}else save();
    }}]);
}
function delMbr(id){
  var m=gM(id);if(!m)return;
  var myRole=_HR_ROLE||CU.role;
  // Protéger AdminFS et les rôles admin/admin_assistant
  if(m.username.toLowerCase()==='adminfs'){
    return alert('Le compte AdminFS ne peut pas être supprimé.');
  }
  if(m.role==='admin'&&myRole!=='admin'){
    return alert('Seul un Admin peut supprimer un compte Admin.');
  }
  if(m.role==='admin_assistant'&&myRole!=='admin'&&myRole!=='admin_assistant'){
    return alert('Seul un Admin ou Admin Assistant peut supprimer un compte Admin Assistant.');
  }
  if(!confirm('Supprimer ce membre définitivement ? Cette action est irréversible.'))return;
  sbDeleteMember(id).then(function(){
    // Also remove from all groups
    var grpSaves=[];
    DB.groups.forEach(function(g){
      if((g.members||[]).indexOf(id)>=0){
        g.members=g.members.filter(function(mid){return mid!==id;});
        grpSaves.push(sbSaveGroup(g));
      }
    });
    Promise.all(grpSaves).then(function(){
      sbLoad().then(function(){go('mbr');});
    });
  }).catch(function(e){console.warn('[delMbr]',e);alert('Erreur suppression.');});
}

