function saveMetaUnits(){
  var existing=(DB.metaUnits||[]);
  sbSaveSettings('meta_units', existing);
}

function toggleMetaUnit(name){
  if(!HR('formation')&&!HR('officier')&&!HR('admin')) return;
  DB.metaUnits=DB.metaUnits||[];
  var idx=DB.metaUnits.indexOf(name);
  if(idx>=0) DB.metaUnits.splice(idx,1);
  else DB.metaUnits.push(name);
  saveMetaUnits();
  _rerenderUnit();
}


function pgUnit(){
  var myU=CU.units||[];
  var myN=myU.map(function(u){return u.name;});
  var activeFilter=window._unitFilter||'';
  var activeSearch=window._unitSearch||'';

  // Tact buttons
  document.getElementById('tact').innerHTML=
    '<button class="btn bol bsm" onclick="openUnitStatsW()" style="margin-right:4px">📊 Stats Maison</button>'
    +'<button class="btn bol bsm" onclick="openUnitSearchW()">🔍 Qui a quoi</button>';

  // Bloc d'information
  var infoH='<div style="background:rgba(201,162,39,.07);border:1px solid var(--golddim);border-radius:4px;padding:14px 18px;margin-bottom:20px;line-height:1.8">'
    +'<div style="font-family:\'Cinzel\',serif;font-size:11px;font-weight:700;color:var(--gold);letter-spacing:1px;margin-bottom:8px">⚔️ COMMENT CHOISIR TES UNITÉS</div>'
    +'<div style="font-size:12px;color:var(--tx2);display:flex;flex-direction:column;gap:5px">'
    +'<div>📋 Sélectionne toutes les unités que tu maîtrises. Les unités taguées <strong style="color:var(--gold)">META</strong> sont prioritaires pour la méta actuelle.</div>'
    +'<div style="margin-top:6px">⭐ <strong style="color:var(--tx1)">Signification des étoiles</strong></div>'
    +'<div style="margin-left:12px;display:flex;flex-direction:column;gap:2px;margin-top:4px;font-size:11px">'
    +'<div>★☆☆☆☆ Possédée, peu ou jamais jouée — impact nul</div>'
    +'<div>★★☆☆☆ Jouée occasionnellement, en apprentissage — impact faible</div>'
    +'<div>★★★☆☆ Maîtrisée, jouée régulièrement — <strong style="color:var(--tx1)">50% impactant</strong></div>'
    +'<div>★★★★☆ Très à l\'aise, unité de confiance — <strong style="color:var(--tx1)">70% impactant</strong></div>'
    +'<div>★★★★★ Doctrinée, maîtrise totale, ta signature — <strong style="color:#66bb6a">impact garanti</strong></div>'
    +'</div>'
    +'<div style="margin-top:8px;padding:8px 10px;background:rgba(139,26,10,.15);border:1px solid var(--red2);border-radius:3px;color:var(--red3)">⚠️ Sois honnête dans ton évaluation. Les officiers utilisent ces données pour construire les groupes de combat. Une auto-évaluation gonflée se verra en guerre et c\'est toi qui en répondras.</div>'
    +'</div>'
    +'</div>';

  // My units list
  var listH=myU.length===0?'<div class="td tsm">Aucune unité sélectionnée.</div>'
    :'<table><thead><tr><th>Unité</th><th>Maîtrise</th><th></th></tr></thead><tbody>'
    +myU.map(function(u,i){
      var rs=unitRarityStyle(u.name);
      return'<tr>'
        +(function(){var im=(DB.metaUnits||[]).indexOf(u.name)>=0; return'<td style="font-size:12px"><span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:'+rs.border+';margin-right:6px"></span>'+esc(u.name)+(im?'<span style="font-size:8px;font-weight:700;background:#c9a227;color:#000;padding:1px 4px;border-radius:2px;margin-left:4px">META</span>':'')+'</td>';})() +''
        +'<td><div style="display:flex;gap:2px">'+[1,2,3,4,5].map(function(n){return'<span style="font-size:16px;cursor:pointer;color:'+(u.mastery>=n?'var(--gold)':'var(--tx3)')+'" onclick="setM('+i+','+n+')">'+(u.mastery>=n?'★':'☆')+'</span>';}).join('')+'</div></td>'
        +'<td><button class="btn bred bsm" onclick="remU('+i+')">✕</button></td>'
        +'</tr>';
    }).join('')+'</tbody></table>';

  // Filter buttons
  var tiers=Object.keys(UC);
  var filterH='<div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:10px">'
    +'<button class="btn '+(activeFilter===''?'bg':'bol')+' bsm" data-t="" onclick="setUnitFilter(this.dataset.t)">Tous</button>'
    +tiers.map(function(t){
      var label=t.split('—')[0].trim();
      var active=activeFilter===t;
      var rs=RARITY_STYLE[t.indexOf('5')>=0?'o':t.indexOf('4')>=0?'m':t.indexOf('3')>=0?'v':t.indexOf('1')>=0?'w':'g'];
      return'<button class="btn '+(active?'bg':'bol')+' bsm" data-t="'+esc(t)+'" onclick="setUnitFilter(this.dataset.t)" style="'+(active?'border-color:'+rs.border+';color:'+rs.color:'')+'">'+label+'</button>';
    }).join('')
    +'</div>'
    +'<div style="margin-bottom:12px"><input class="fi" id="unit-search" placeholder="🔍 Rechercher une unité..." value="'+esc(activeSearch)+'" oninput="setUnitSearch(this.value)" style="font-size:13px"></div>';

  // Catalogue filtered
  var catH='';
  Object.entries(UC).forEach(function(entry){
    var tier=entry[0], units=entry[1];
    if(activeFilter && activeFilter!==tier) return;
    var filtered=activeSearch?units.filter(function(u){return u.toLowerCase().indexOf(activeSearch.toLowerCase())>=0;}):units;
    if(!filtered.length) return;
    var rs=RARITY_STYLE[tier.indexOf('5')>=0?'o':tier.indexOf('4')>=0?'m':tier.indexOf('3')>=0?'v':tier.indexOf('1')>=0?'w':'g'];
    catH+='<div style="margin-bottom:16px">'
      +'<div style="font-size:10px;font-weight:700;color:'+rs.color+';letter-spacing:2px;text-transform:uppercase;margin-bottom:6px;padding:4px 8px;background:'+rs.bg+';border-left:3px solid '+rs.border+';border-radius:2px">'+tier+'</div>'
      +'<div class="uc-grid">'
      +filtered.map(function(u){
        var sel=myN.indexOf(u)>=0;
        var rs2=unitRarityStyle(u);
        var isMeta=(DB.metaUnits||[]).indexOf(u)>=0;
        return'<div class="uchip'+(sel?' sel':'')+'" onclick="togUnitW(this)" data-u="'+esc(u)+'"'
          +' style="border-color:'+(isMeta?'#c9a227':rs2.border)+';background:'+(sel?rs2.bg.replace(',.12',',0.25'):rs2.bg)+';color:'+(sel?rs2.color:'var(--tx2)')+';">'
          +(isMeta?'<span style="font-size:8px;font-weight:700;background:#c9a227;color:#000;padding:1px 4px;border-radius:2px;margin-right:4px;vertical-align:middle">META</span>':'')
          +(sel?'✓ ':'')+esc(u)
          +((HR('formation')||HR('officier')||HR('admin'))?'<span onclick="toggleMetaUnit(this.dataset.u);event.stopPropagation()" data-u="'+esc(u)+'" title="'+(isMeta?'Retirer META':'Marquer META')+'" style="margin-left:5px;font-size:10px;cursor:pointer;opacity:0.6;vertical-align:middle">'+(isMeta?'★':'☆')+'</span>':'')
          +'</div>';
      }).join('')
      +'</div></div>';
  });

  if(!catH) catH='<div class="td tsm" style="padding:20px">Aucune unité trouvée.</div>';

  return infoH
    +'<div class="g2">'
    +'<div><div class="pan"><div class="ph"><span class="ptl">Mes Unités ('+myU.length+')</span></div><div class="pb">'+listH+'</div></div></div>'
    +'<div><div class="pan"><div class="ph"><span class="ptl">Catalogue</span></div><div class="pb">'+filterH+catH+'</div></div></div>'
    +'</div>';
}

function setUnitFilter(f){
  window._unitFilter=f||'';
  _rerenderUnit();
}
function setUnitSearch(v){window._unitSearch=v;
  // Re-render catalogue only without full page reload
  var content=document.getElementById('content');
  if(content) content.innerHTML=pgUnit();
  // Restore focus
  var inp=document.getElementById('unit-search');
  if(inp){inp.focus();inp.setSelectionRange(inp.value.length,inp.value.length);}
}

