function setCalTab(t){window._calTab=t;try{sessionStorage.setItem('calTab',t);}catch(e){}window._calDetail=null;go('cal');}

// ── Votes participation événements ───────────────────────────
function castEventVote(btn){
  var id=btn.dataset.id;
  var e=(DB.events||[]).find(function(x){return x.id===id;});
  if(!e||!e.voteOpen) return;
  e.votes=e.votes||{};
  // Toggle : si déjà inscrit → retirer, sinon → inscrire
  if(e.votes[CU.id]===true||e.votes[CU.id]==='present'){
    delete e.votes[CU.id];
  } else {
    e.votes[CU.id]=true;
  }
  sbSaveEvent(e).then(function(){
    window._calDetail={type:'event',data:e};
    go('cal');
  }).catch(function(err){console.warn('[eventVote]',err);});
}

function toggleEventVoteW(btn){ toggleEventVote(btn.dataset.id); }
function toggleEventVote(id){
  if(!HR('evenement')&&!HR('officier')) return;
  var e=(DB.events||[]).find(function(x){return x.id===id;});
  if(!e) return;
  e.voteOpen=!e.voteOpen;
  sbSaveEvent(e).then(function(){
    window._calDetail={type:'event',data:e};
    go('cal');
  }).catch(function(err){console.warn('[toggleEventVote]',err);});
}


function openCalDetail(el){
  var id=el.dataset.id, type=el.dataset.type;
  if(type==='event'){
    var e=(DB.events||[]).find(function(x){return x.id===id;});
    if(e){window._calDetail={type:'event',data:e};go('cal');}
  } else if(type==='tournament'){
    var t=(DB.tournaments||[]).find(function(x){return x.id===id;});
  } else if(type==='training'){
    var tr=(DB.trainings||[]).find(function(x){return x.id===id;});
    if(tr){window._calDetail={type:'training',data:tr};go('cal');}
    if(t){window._calDetail={type:'tournament',data:t};go('cal');}
  }
}

function renderCalDetail(detail){
  var backBtn='<div style="margin-bottom:12px"><button class="btn bol bsm" onclick="window._calDetail=null;go(\'cal\')">← Retour</button></div>';
  if(detail.type==='event'){
    var e=detail.data;
    var canManage=HR('evenement')||HR('officier');
    var votes=e.votes||{};
    var myIn=votes[CU.id]===true||votes[CU.id]==='present';
    var participants=DB.members.filter(function(m){
      return m.status!=='attente'&&(votes[m.id]===true||votes[m.id]==='present');
    }).sort(function(a,b){return a.username.localeCompare(b.username);});

    var voteSection='';
    if(e.voteOpen){
      voteSection='<div style="margin-bottom:16px">'
        +'<div style="display:flex;align-items:center;gap:12px;margin-bottom:14px">'
        +'<button onclick="castEventVote(this)" data-id="'+e.id+'" style="'
        +(myIn?'background:rgba(56,142,60,.2);border-color:#388e3c;color:#66bb6a;':'')
        +'padding:10px 24px;font-size:13px;font-family:Cinzel,serif;font-weight:700;cursor:pointer;border-radius:3px;border:1px solid var(--b2);color:var(--tx2);transition:all .2s" class="btn '+(myIn?'':'bol')+'">'
        +(myIn?'✅ Je participe — Retirer':'🙋 Je participe')+'</button>'
        +'<span style="font-size:12px;color:var(--tx3)">'+participants.length+' participant(s)</span>'
        +'</div>'
        +'<div style="background:rgba(46,125,50,.06);border:1px solid rgba(56,142,60,.25);border-radius:3px;padding:10px">'
        +'<div style="font-size:10px;font-weight:700;color:#66bb6a;letter-spacing:1px;margin-bottom:8px">PARTICIPANTS ('+participants.length+')</div>'
        +(participants.length===0?'<div style="font-size:11px;color:var(--tx3)">Aucun participant pour l\'instant.</div>':'')
        +participants.map(function(m){return'<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px">'+avaHTML(m,20)+'<span style="font-size:12px;color:var(--tx1)">'+esc(m.username)+'</span></div>';}).join('')
        +'</div>'
        +'</div>';
    } else if(Object.keys(votes).length){
      voteSection='<div style="margin-bottom:16px;background:rgba(46,125,50,.06);border:1px solid rgba(56,142,60,.25);border-radius:3px;padding:12px">'
        +'<div style="font-size:10px;font-weight:700;color:#66bb6a;letter-spacing:1px;margin-bottom:8px">PARTICIPANTS ('+participants.length+')</div>'
        +(participants.length===0?'<div style="font-size:11px;color:var(--tx3)">Aucun participant.</div>':'')
        +participants.map(function(m){return'<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px">'+avaHTML(m,20)+'<span style="font-size:12px;color:var(--tx1)">'+esc(m.username)+'</span></div>';}).join('')
        +'</div>';
    }

    return backBtn
      +'<div class="pan"><div class="ph"><span class="ptl" style="font-size:16px">'+esc(e.title)+'</span>'
      +'<div style="display:flex;gap:6px;margin-left:auto">'
      +(e.voteOpen?'<span style="font-size:10px;font-weight:700;color:#66bb6a;border:1px solid #388e3c;padding:2px 8px;border-radius:3px">VOTE OUVERT</span>':'')
      +(canManage?'<button class="btn bol bsm" onclick="toggleEventVoteW(this)" data-id="'+e.id+'">'+(e.voteOpen?'🔒 Clôturer vote':'📋 Ouvrir vote')+'</button>':'')
      +(canManage?'<button class="btn bol bsm" onclick="editEventW(this)" data-id="'+e.id+'">✏️</button>':'')
      +'</div>'
      +'</div>'
      +(e.image?'<div style="width:100%;height:220px;overflow:hidden;border-radius:3px;margin-bottom:12px"><img src="'+esc(e.image)+'" style="width:100%;height:100%;object-fit:cover"></div>':'')
      +'<div class="pb"><div style="display:flex;gap:16px;font-size:12px;color:var(--tx3);margin-bottom:12px">'
      +'<span>📅 '+esc(e.date)+'</span><span>🕐 '+esc(e.time)+'</span></div>'
      +(e.description?'<div style="font-size:14px;line-height:1.8;white-space:pre-line;margin-bottom:12px">'+esc(e.description)+'</div>':'')
      +voteSection
      +'</div></div>';
  } else if(detail.type==='tournament'){
    return backBtn + renderTournamentDetail(detail.data);
  } else if(detail.type==='training'){
    return backBtn + renderTrainingDetail(detail.data);
  }
}


// ══════════════════════════════════════════════════════
// ENTRAÎNEMENTS
// ══════════════════════════════════════════════════════

function renderTrainingDetail(tr){
  var canManage=HR('evenement')||HR('officier');
  var myIn=tr.registrations&&tr.registrations[CU.id];
  var registeredIds=Object.keys(tr.registrations||{}).filter(function(k){return tr.registrations[k];});
  var registeredMembers=DB.members.filter(function(m){return registeredIds.indexOf(m.id)>=0;});
  var statusColor=tr.status==='open'?'#66bb6a':tr.status==='ongoing'?'#f9a825':'var(--tx3)';
  var statusLabel=tr.status==='open'?'Inscriptions ouvertes':tr.status==='ongoing'?'En cours':'Terminé';

  // Inscription button
  var regSection='';
  if(tr.status==='open'){
    regSection='<div style="margin-bottom:16px;display:flex;align-items:center;gap:12px;flex-wrap:wrap">'
      +'<button onclick="castTrainingReg(this)" data-id="'+tr.id+'" style="'
      +(myIn?'background:rgba(56,142,60,.2);border-color:#388e3c;color:#66bb6a;':'')
      +'padding:10px 24px;font-size:13px;font-family:Cinzel,serif;font-weight:700;cursor:pointer;border-radius:3px;border:1px solid var(--b2);color:var(--tx2);transition:all .2s" class="btn '+(myIn?'':'bol')+'">'
      +(myIn?'✅ Inscrit — Retirer':'🙋 S\'inscrire')+'</button>'
      +'<span style="font-size:12px;color:var(--tx3)">'+registeredIds.length+' inscrit(s)</span>'
      +'</div>';
  }

  // Participants list
  var partSection='<div style="background:rgba(46,125,50,.06);border:1px solid rgba(56,142,60,.25);border-radius:3px;padding:10px;margin-bottom:16px">'
    +'<div style="font-size:10px;font-weight:700;color:#66bb6a;letter-spacing:1px;margin-bottom:8px">INSCRITS ('+registeredMembers.length+')</div>'
    +(registeredMembers.length===0?'<div style="font-size:11px;color:var(--tx3)">Aucun inscrit pour l\'instant.</div>':'')
    +registeredMembers.map(function(m){return'<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px">'+avaHTML(m,20)+'<span style="font-size:12px;color:var(--tx1)">'+esc(m.username)+'</span></div>';}).join('')
    +'</div>';

  // Teams section
  var teamsSection='';
  if(tr.teams&&tr.teams.length){
    teamsSection='<div style="margin-bottom:16px">'
      +'<div style="font-size:10px;font-weight:700;color:var(--tx3);letter-spacing:1px;margin-bottom:10px">ÉQUIPES</div>'
      +'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:10px">'
      +tr.teams.map(function(team){
        return'<div style="background:var(--bg2);border:1px solid var(--b2);border-radius:4px;padding:10px">'
          +'<div style="font-family:Cinzel,serif;font-size:11px;font-weight:700;color:var(--gold);margin-bottom:8px">'+esc(team.name)+'</div>'
          +(team.members||[]).map(function(tm){
            var m=gM(tm.memberId);
            var metaList=DB.metaUnits||[];
            var units=tm.units||[];
            return'<div style="margin-bottom:6px">'
              +(m?'<div style="display:flex;align-items:center;gap:5px;margin-bottom:3px">'+avaHTML(m,16)+'<span style="font-size:11px;color:var(--tx1)">'+esc(m.username)+'</span></div>':'')
              +'<div style="display:flex;gap:3px;flex-wrap:wrap;padding-left:21px">'
              +[0,1,2].map(function(ui){
                var u=units[ui]||'';
                var isMeta=u&&metaList.indexOf(u)>=0;
                if(!u) return'<span style="font-size:9px;color:var(--tx4);border:1px dashed var(--b1);padding:1px 5px;border-radius:2px">U'+(ui+1)+'</span>';
                return'<span style="font-size:9px;padding:1px 5px;border-radius:2px;'+(isMeta?'background:rgba(201,162,39,.2);color:var(--gold);border:1px solid rgba(201,162,39,.4)':'background:var(--bg1);color:var(--tx2);border:1px solid var(--b1)')+'">'+(isMeta?'★ ':'')+esc(u)+'</span>';
              }).join('')
              +'</div></div>';
          }).join('')
          +'</div>';
      }).join('')
      +'</div></div>';
  }

  // My units assignment (if in a team)
  var myTeam=null, myTeamIdx=-1, myMemberSlot=null;
  if(tr.teams) tr.teams.forEach(function(team,ti){
    team.members&&team.members.forEach(function(tm){
      if(tm.memberId===CU.id){myTeam=team;myTeamIdx=ti;myMemberSlot=tm;}
    });
  });

  var myUnitsSection='';
  if(myTeam&&myMemberSlot){
    var metaList=DB.metaUnits||[];
    var myAllUnits=CU.units||[];
    var myMetaUnits=myAllUnits.filter(function(u){return metaList.indexOf(u.name)>=0;});
    var myOtherUnits=myAllUnits.filter(function(u){return metaList.indexOf(u.name)<0;});
    var optFn=function(u){var rs=unitRarityStyle(u.name);return'<option value="'+esc(u.name)+'" style="color:'+rs.color+';background:var(--bg1)">'+esc(u.name)+' '+'★'.repeat(u.mastery||0)+'</option>';};
    myUnitsSection='<div style="background:rgba(201,162,39,.07);border:1px solid var(--golddim);border-radius:4px;padding:14px;margin-bottom:16px">'
      +'<div style="font-size:10px;font-weight:700;color:var(--gold);letter-spacing:1px;margin-bottom:10px">⚔️ MES UNITÉS POUR CET ENTRAÎNEMENT ('+esc(myTeam.name)+')</div>'
      +'<div style="display:flex;gap:8px;flex-wrap:wrap">'
      +[0,1,2].map(function(ui){
        var curU=(myMemberSlot.units||[])[ui]||'';
        var selColor=curU?unitRarityStyle(curU).color:'var(--tx2)';
        return'<div style="flex:1;min-width:120px">'
          +'<div style="font-size:9px;color:var(--tx3);margin-bottom:4px">Unité '+(ui+1)+'</div>'
          +'<select onchange="setTrainingUnit(this)" data-trid="'+tr.id+'" data-ti="'+myTeamIdx+'" data-ui="'+ui+'" style="width:100%;font-size:11px;background:var(--bg1);border:1px solid var(--b2);color:'+selColor+';border-radius:3px;padding:4px">'
          +'<option value="">— Choisir —</option>'
          +(myMetaUnits.length?'<optgroup label="★ META">'+myMetaUnits.map(optFn).join('')+'</optgroup>':'')
          +(myOtherUnits.length?'<optgroup label="Autres">'+myOtherUnits.map(optFn).join('')+'</optgroup>':'')
          +'</select></div>';
      }).join('')
      +'</div>'
      +'<button onclick="saveTrainingUnits(this)" data-trid="'+tr.id+'" data-ti="'+myTeamIdx+'" class="btn bg bsm" style="margin-top:10px">💾 Sauvegarder mes unités</button>'
      +'</div>';
    // Pre-select current values via postrender
    setTimeout(function(){
      [0,1,2].forEach(function(ui){
        var sel=document.querySelector('select[data-trid="'+tr.id+'"][data-ti="'+myTeamIdx+'"][data-ui="'+ui+'"]');
        if(sel){sel.value=(myMemberSlot.units||[])[ui]||'';setUnitElColor(sel);}
      });
    },50);
  }

  var h='<div class="pan" style="margin-bottom:12px">'
    +'<div class="ph"><span style="font-size:18px;margin-right:8px">🥊</span>'
    +'<span class="ptl" style="font-size:16px">'+esc(tr.title)+'</span>'
    +'<span style="margin-left:8px;font-size:10px;font-weight:700;color:'+statusColor+'">'+statusLabel+'</span>'
    +(canManage?'<div style="margin-left:auto;display:flex;gap:6px">'
      +(tr.status!=='finished'?'<button class="btn bol bsm" onclick="openTrainingTeamBuilder(this.dataset.id)" data-id="'+tr.id+'">👥 Équipes</button>':'' )
      +'<button class="btn bol bsm" onclick="cycleTrainingStatus(this.dataset.id)" data-id="'+tr.id+'">'+(tr.status==='open'?'▶ En cours':tr.status==='ongoing'?'✅ Terminer':'🔄 Rouvrir')+'</button>'
      +'<button class="btn bol bsm" onclick="editTrainingW2(this.dataset.id)" data-id="'+tr.id+'">✏️</button>'
      +'</div>':'')
    +'</div>'
    +'<div class="pb">'
    +'<div style="display:flex;gap:16px;font-size:12px;color:var(--tx3);margin-bottom:12px">'
    +'<span>📅 '+esc(tr.date)+'</span><span>🕐 '+esc(tr.time)+'</span>'
    +(tr.teamSize?'<span>👥 '+tr.teamSize+' par équipe</span>':'')
    +'</div>'
    +(tr.description?'<div style="font-size:14px;line-height:1.8;margin-bottom:12px">'+esc(tr.description)+'</div>':'')
    +regSection
    +myUnitsSection
    +partSection
    +teamsSection
    +'</div></div>';
  return h;
}

function castTrainingReg(btn){
  var id=btn.dataset.id;
  var tr=(DB.trainings||[]).find(function(x){return x.id===id;});
  if(!tr||tr.status!=='open') return;
  tr.registrations=tr.registrations||{};
  if(tr.registrations[CU.id]) delete tr.registrations[CU.id];
  else tr.registrations[CU.id]=true;
  sbSaveTraining(tr).then(function(){window._calDetail={type:'training',data:tr};go('cal');}).catch(function(e){console.warn(e);});
}

function cycleTrainingStatus(id){
  var tr=(DB.trainings||[]).find(function(x){return x.id===id;});
  if(!tr) return;
  var next=tr.status==='open'?'ongoing':tr.status==='ongoing'?'finished':'open';
  if(!confirm('Passer le statut en "'+next+'" ?')) return;
  tr.status=next;
  sbSaveTraining(tr).then(function(){window._calDetail={type:'training',data:tr};go('cal');}).catch(function(e){console.warn(e);});
}

function setTrainingUnit(sel){
  setUnitElColor(sel);
}

function saveTrainingUnits(btn){
  var trid=btn.dataset.trid, ti=parseInt(btn.dataset.ti);
  var tr=(DB.trainings||[]).find(function(x){return x.id===trid;});
  if(!tr||!tr.teams[ti]) return;
  var tm=tr.teams[ti].members.find(function(m){return m.memberId===CU.id;});
  if(!tm) return;
  tm.units=[0,1,2].map(function(ui){
    var sel=document.querySelector('select[data-trid="'+trid+'"][data-ti="'+ti+'"][data-ui="'+ui+'"]');
    return sel?sel.value:'';
  });
  sbSaveTraining(tr).then(function(){window._calDetail={type:'training',data:tr};go('cal');}).catch(function(e){alert('Erreur sauvegarde');console.warn(e);});
}

function openTrainingTeamBuilder(id){
  var tr=(DB.trainings||[]).find(function(x){return x.id===id;});
  if(!tr) return;
  var registeredIds=Object.keys(tr.registrations||{}).filter(function(k){return tr.registrations[k];});
  if(registeredIds.length<2){alert('Il faut au moins 2 inscrits pour former des équipes.');return;}
  if(!tr.teams||!tr.teams.length){
    var ts=tr.teamSize||5;
    var nb=Math.max(2,Math.ceil(registeredIds.length/ts));
    tr.teams=[];
    for(var i=0;i<nb;i++) tr.teams.push({id:'trt'+Date.now()+i,name:'Équipe '+(i+1),members:[]});
  }
  renderTrainingTeamBuilder(tr);
}

function renderTrainingTeamBuilder(tr){
  var registeredIds=Object.keys(tr.registrations||{}).filter(function(k){return tr.registrations[k];});
  var teams=tr.teams||[];
  var sel=window._trtSelected||null;
  var assignedIds=[];
  teams.forEach(function(team){(team.members||[]).forEach(function(m){assignedIds.push(m.memberId);});});
  var unassigned=registeredIds.filter(function(id){return assignedIds.indexOf(id)<0;});

  var html='<div style="margin-bottom:12px;display:flex;gap:8px;align-items:center;flex-wrap:wrap">'
    +'<span style="font-size:11px;color:var(--tx3)">Cliquez un joueur puis une équipe pour l\'assigner.</span>'
    +'<button onclick="autoFillTrainingTeams(\''+tr.id+'\')" class="btn bol bsm" style="margin-left:auto">⚡ Auto-répartir</button>'
    +'</div>';

  html+='<div style="margin-bottom:14px"><div style="font-size:10px;font-weight:700;color:var(--tx3);letter-spacing:1px;margin-bottom:6px">NON ASSIGNÉS ('+unassigned.length+')</div>';
  html+='<div style="display:flex;flex-wrap:wrap;gap:6px">';
  unassigned.forEach(function(mid){
    var m=gM(mid);
    var isSelected=sel===mid;
    html+='<div onclick="trtSelectPlayer(this)" data-trid="'+tr.id+'" data-pid="'+mid+'" style="cursor:pointer;border-radius:3px;padding:5px 10px;font-size:12px;display:flex;align-items:center;gap:6px;transition:all .15s;'
      +(isSelected?'background:var(--golddim);border:2px solid var(--gold);color:var(--gold);':'background:var(--bg2);border:2px solid var(--b2);color:var(--tx1);')
      +'">'
      +(m?avaHTML(m,18):mid)+(m?esc(m.username):mid)
      +(isSelected?'<span style="font-size:10px">✓</span>':'')
      +'</div>';
  });
  html+='</div></div>';

  html+='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:10px;margin-bottom:14px">';
  teams.forEach(function(team,ti){
    var canAdd=sel&&!false;
    html+='<div onclick="trtDropToTeam(this)" data-trid="'+tr.id+'" data-ti="'+ti+'" style="background:var(--bg1);border:2px solid '+(canAdd&&sel?'var(--gold)':'var(--b2)')+';border-radius:4px;padding:10px;cursor:'+(canAdd&&sel?'pointer':'default')+';transition:border-color .15s">';
    html+='<input style="width:100%;background:transparent;border:none;border-bottom:1px solid var(--b2);color:var(--gold);font-family:Cinzel,serif;font-size:11px;font-weight:700;padding:2px 0;margin-bottom:8px" value="'+esc(team.name)+'" onclick="event.stopPropagation()" onchange="renameTrtTeam(this)" data-trid="'+tr.id+'" data-ti="'+ti+'">';
    if(!team.members||team.members.length===0){
      html+='<div style="font-size:11px;color:var(--tx3);text-align:center;padding:6px 0">'+(sel?'👆 Cliquer pour ajouter':'Vide')+'</div>';
    }
    (team.members||[]).forEach(function(tm){
      var m=gM(tm.memberId);
      html+='<div style="display:flex;align-items:center;gap:5px;margin-bottom:4px;font-size:11px;color:var(--tx1)">'
        +(m?avaHTML(m,16):'')+(m?esc(m.username):tm.memberId)
        +'<button onclick="trtRemovePlayer(this);event.stopPropagation()" data-trid="'+tr.id+'" data-pid="'+tm.memberId+'" data-ti="'+ti+'" style="margin-left:auto;background:none;border:none;color:var(--red3);cursor:pointer;font-size:11px;padding:0">✕</button>'
        +'</div>';
    });
    html+='<div style="font-size:9px;color:var(--tx3);text-align:right;margin-top:4px">'+(team.members||[]).length+' membre(s)</div>';
    html+='</div>';
  });
  html+='</div>';

  OM('Équipes — '+esc(tr.title), html,
    [{lbl:'Annuler',cls:'bol',fn:function(){window._trtSelected=null;CM();}},
     {lbl:'+ Équipe',cls:'btn bol',fn:function(){
       tr.teams=tr.teams||[];
       tr.teams.push({id:'trt'+Date.now(),name:'Équipe '+(tr.teams.length+1),members:[]});
       window._trtSelected=null;
       renderTrainingTeamBuilder(tr);
     }},
     {lbl:'💾 Sauvegarder',cls:'btn bg',fn:function(){
       window._trtSelected=null;CM();
       sbSaveTraining(tr).then(function(){window._calDetail={type:'training',data:tr};go('cal');}).catch(function(e){console.warn(e);});
     }}]);
}

function trtSelectPlayer(el){
  var pid=el.dataset.pid;
  var tr=(DB.trainings||[]).find(function(x){return x.id===el.dataset.trid;});
  if(!tr) return;
  window._trtSelected=(window._trtSelected===pid)?null:pid;
  renderTrainingTeamBuilder(tr);
}

function trtDropToTeam(el){
  if(!window._trtSelected) return;
  var tr=(DB.trainings||[]).find(function(x){return x.id===el.dataset.trid;});
  if(!tr) return;
  var ti=parseInt(el.dataset.ti);
  var team=tr.teams[ti];
  if(!team) return;
  var alreadyIn=false;
  tr.teams.forEach(function(te){(te.members||[]).forEach(function(m){if(m.memberId===window._trtSelected)alreadyIn=true;});});
  if(alreadyIn) return;
  team.members=team.members||[];
  team.members.push({memberId:window._trtSelected,units:[]});
  window._trtSelected=null;
  renderTrainingTeamBuilder(tr);
}

function trtRemovePlayer(btn){
  var tr=(DB.trainings||[]).find(function(x){return x.id===btn.dataset.trid;});
  if(!tr) return;
  var ti=parseInt(btn.dataset.ti);
  tr.teams[ti].members=(tr.teams[ti].members||[]).filter(function(m){return m.memberId!==btn.dataset.pid;});
  window._trtSelected=null;
  renderTrainingTeamBuilder(tr);
}

function renameTrtTeam(inp){
  var tr=(DB.trainings||[]).find(function(x){return x.id===inp.dataset.trid;});
  if(!tr) return;
  var ti=parseInt(inp.dataset.ti);
  if(tr.teams[ti]) tr.teams[ti].name=inp.value;
}

function autoFillTrainingTeams(id){
  var tr=(DB.trainings||[]).find(function(x){return x.id===id;});
  if(!tr) return;
  var registeredIds=Object.keys(tr.registrations||{}).filter(function(k){return tr.registrations[k];});
  var ts=tr.teamSize||5;
  var nb=Math.max(2,Math.ceil(registeredIds.length/ts));
  // Shuffle
  var ids=registeredIds.slice();
  for(var i=ids.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var tmp=ids[i];ids[i]=ids[j];ids[j]=tmp;}
  tr.teams=[];
  for(var k=0;k<nb;k++){
    tr.teams.push({id:'trt'+Date.now()+k,name:'Équipe '+(k+1),members:ids.slice(k*ts,(k+1)*ts).map(function(mid){return{memberId:mid,units:[]};})});
  }
  window._trtSelected=null;
  renderTrainingTeamBuilder(tr);
}

function openNewTraining(){
  var canManage=HR('evenement')||HR('officier');
  if(!canManage) return;
  OM('Nouvel entraînement',
    '<div class="fg"><label class="fl">Titre</label><input class="fi" id="ntr-title"></div>'
    +'<div class="fg"><label class="fl">Description</label><textarea class="ft" id="ntr-desc" style="min-height:60px"></textarea></div>'
    +'<div class="fr2"><div class="fg"><label class="fl">Date</label><input class="fi" type="date" id="ntr-date" value="'+nowDate()+'"></div>'
    +'<div class="fg"><label class="fl">Heure</label><input class="fi" type="time" id="ntr-time" value="20:00"></div></div>'
    +'<div class="fg"><label class="fl">Membres par équipe</label><input class="fi" type="number" id="ntr-teamsize" value="5" min="1" max="30" style="max-width:100px"><span style="font-size:11px;color:var(--tx3);margin-left:8px">ex: 5 pour 5v5</span></div>',
    [{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'Créer',cls:'btn bg',fn:function(){
      var title=gVal('ntr-title').trim();if(!title)return alert('Titre requis');
      var tr={
        id:'tr'+Date.now(), title:title, description:gVal('ntr-desc'),
        date:gVal('ntr-date'), time:gVal('ntr-time'),
        teamSize:parseInt(gVal('ntr-teamsize'))||5,
        status:'open', registrations:{}, teams:[],
        createdBy:CU.username
      };
      DB.trainings=DB.trainings||[];
      DB.trainings.push(tr);
      sbSaveTraining(tr).catch(function(e){console.warn(e);});
      CM();window._calDetail={type:'training',data:tr};go('cal');
    }}]);
}

function editTrainingW(el){
  var tr=(DB.trainings||[]).find(function(x){return x.id===el.dataset.id;});
  if(!tr) return; editTrainingForm(tr);
}
function editTrainingW2(id){
  var tr=(DB.trainings||[]).find(function(x){return x.id===id;});
  if(!tr) return; editTrainingForm(tr);
}
function editTrainingForm(tr){
  OM('Modifier l\'entraînement',
    '<div class="fg"><label class="fl">Titre</label><input class="fi" id="etr-title" value="'+esc(tr.title)+'"></div>'
    +'<div class="fg"><label class="fl">Description</label><textarea class="ft" id="etr-desc">'+esc(tr.description||'')+'</textarea></div>'
    +'<div class="fr2"><div class="fg"><label class="fl">Date</label><input class="fi" type="date" id="etr-date" value="'+esc(tr.date)+'"></div>'
    +'<div class="fg"><label class="fl">Heure</label><input class="fi" type="time" id="etr-time" value="'+esc(tr.time)+'"></div></div>'
    +'<div class="fr2"><div class="fg"><label class="fl">Membres par équipe</label><input class="fi" type="number" id="etr-teamsize" value="'+(tr.teamSize||5)+'" min="1" max="30" style="max-width:100px"></div>'
    +'<div class="fg"><label class="fl">Statut</label><select class="fs" id="etr-status"><option value="open"'+(tr.status==='open'?' selected':'')+'>Inscriptions ouvertes</option><option value="ongoing"'+(tr.status==='ongoing'?' selected':'')+'>En cours</option><option value="finished"'+(tr.status==='finished'?' selected':'')+'>Terminé</option></select></div></div>',
    [{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'Sauvegarder',cls:'btn bg',fn:function(){
      tr.title=gVal('etr-title')||tr.title;
      tr.description=gVal('etr-desc');
      tr.date=gVal('etr-date'); tr.time=gVal('etr-time');
      tr.teamSize=parseInt(gVal('etr-teamsize'))||tr.teamSize||5;
      tr.status=gVal('etr-status');
      sbSaveTraining(tr).catch(function(e){console.warn(e);});
      CM();window._calDetail={type:'training',data:tr};go('cal');
    }}]);
}

function delTrainingW(el){
  if(!confirm('Supprimer cet entraînement ?')) return;
  var id=el.dataset.id;
  DB.trainings=(DB.trainings||[]).filter(function(x){return x.id!==id;});
  sbDeleteTraining(id).catch(function(e){console.warn(e);});
  window._calDetail=null; go('cal');
}

function renderTournamentDetail(t){
  var canManage=HR('evenement')||HR('officier');
  var myReg=(t.participants||[]).find(function(p){return p.memberId===CU.id;});
  var statusColor=t.status==='open'?'#66bb6a':t.status==='ongoing'?'#f9a825':'var(--tx3)';
  var statusLabel=t.status==='open'?'Inscriptions ouvertes':t.status==='ongoing'?'En cours':'Terminé';
  var canRegister=t.status==='open'&&(t.participants||[]).length<(t.maxParticipants||16);

  var h='<div class="pan" style="margin-bottom:12px">'
    +'<div class="ph"><span style="font-size:18px;margin-right:8px">🏆</span>'
    +'<span class="ptl" style="font-size:16px">'+esc(t.title)+'</span>'
    +'<span style="margin-left:8px;font-size:10px;font-weight:700;color:'+statusColor+'">'+statusLabel+'</span>'
    +'</div>'
    +(t.image?'<div style="width:100%;height:220px;overflow:hidden"><img src="'+esc(t.image)+'" style="width:100%;height:100%;object-fit:cover"></div>':'')
    +'<div class="pb">'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:8px;margin-bottom:16px">'
    +'<div style="background:var(--bg1);border-radius:3px;padding:8px;text-align:center"><div style="font-size:18px">📅</div><div style="font-size:12px;color:var(--tx1)">'+esc(t.date+(t.time?' à '+t.time:''))+'</div><div style="font-size:9px;color:var(--tx3)">Date</div></div>'
    +'<div style="background:var(--bg1);border-radius:3px;padding:8px;text-align:center"><div style="font-size:18px">🎮</div><div style="font-size:12px;color:var(--tx1)">'+(t.type==='1v1'?'Individuel (1v1)':'Équipes ('+(t.teamSize||2)+'v'+(t.teamSize||2)+')')+'</div><div style="font-size:9px;color:var(--tx3)">Type</div></div>'
    +'<div style="background:var(--bg1);border-radius:3px;padding:8px;text-align:center"><div style="font-size:18px">📈</div><div style="font-size:12px;color:var(--tx1)">'+(t.format==='elimination'?'Élim. directe':'Poules')+'</div><div style="font-size:9px;color:var(--tx3)">Format</div></div>'
    +'<div style="background:var(--bg1);border-radius:3px;padding:8px;text-align:center"><div style="font-size:18px">👥</div><div style="font-size:12px;color:var(--tx1)">'+(t.participants||[]).length+'/'+(t.maxParticipants||16)+'</div><div style="font-size:9px;color:var(--tx3)">Inscrits</div></div>'
    +'</div>'
    +(t.description?'<div style="font-size:13px;line-height:1.8;margin-bottom:16px">'+esc(t.description)+'</div>':'')
    // Registration button
    +'<div style="margin-bottom:16px">'
    +(canRegister&&!myReg?'<button class="btn bg" onclick="registerTournament(this.dataset.tid)" data-tid="'+t.id+'">✅ S’inscrire</button>':'')
    +(myReg?'<button class="btn bred" onclick="unregisterTournament(this.dataset.tid)" data-tid="'+t.id+'">❌ Se désinscrire</button>':'')
    +(!canRegister&&!myReg&&t.status==='open'?'<div style="color:var(--red3);font-size:12px">Tournoi complet</div>':'')
    +'</div>'
    +'</div></div>';

  // Participants list
  // Équipes si formées, sinon liste participants
  if(t.type==='team'&&t.teams&&t.teams.length&&t.teams.some(function(te){return te.members.length>0;})){
    h+='<div class="pan" style="margin-bottom:12px"><div class="ph"><span class="ptl">Équipes ('+(t.teamSize||2)+'v'+(t.teamSize||2)+')</span>'
      +(canManage&&t.status==='open'?'<button class="btn bol bsm" style="margin-left:auto" onclick="openTeamBuilderW(this)" data-id="'+t.id+'">✏️ Modifier les équipes</button>':'')
      +'</div><div class="pb"><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:10px">';
    t.teams.forEach(function(team){
      h+='<div style="background:var(--bg1);border:1px solid var(--b2);border-radius:4px;padding:10px">';
      h+='<div style="font-family:Cinzel,serif;font-size:11px;font-weight:700;color:var(--gold);margin-bottom:8px">'+esc(team.name)+'</div>';
      team.members.forEach(function(p){
        var mb=DB.members.find(function(m){return m.id===p.memberId;});
        h+='<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;font-size:11px;color:var(--tx1)">'
          +(mb?avaHTML(mb,18):'')+(mb?esc(mb.username):esc(p.name||'?'))+'</div>';
      });
      h+='</div>';
    });
    h+='</div></div></div>';
  } else {
    // Affichage par équipes si tournoi d'équipes avec équipes formées
    if(t.type==='team'&&(t.teams||[]).length>0){
      h+='<div class="pan" style="margin-bottom:12px"><div class="ph"><span class="ptl">Équipes ('+(t.teams.length)+')</span>'
        +(canManage&&t.status==='open'?'<button class="btn bol bsm" style="margin-left:auto" onclick="openTeamBuilder(window._calDetail.data)">✏️ Modifier</button>':'')
        +'</div><div class="pb"><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:10px">';
      t.teams.forEach(function(team){
        h+='<div style="background:var(--bg1);border:1px solid var(--golddim);border-radius:4px;padding:10px">';
        h+='<div style="font-family:Cinzel,serif;font-size:11px;font-weight:700;color:var(--gold);margin-bottom:8px;border-bottom:1px solid var(--golddim);padding-bottom:4px">'+esc(team.name)+'</div>';
        (team.members||[]).forEach(function(p){
          var mb=DB.members.find(function(m){return m.id===p.memberId;});
          h+='<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;font-size:11px;color:var(--tx1)">'
            +(mb?avaHTML(mb,18):'')+(mb?esc(mb.username):esc(p.name||p.memberId))+'</div>';
        });
        h+='</div>';
      });
      h+='</div></div></div>';
    } else {
      h+='<div class="pan" style="margin-bottom:12px"><div class="ph"><span class="ptl">Participants ('+(t.participants||[]).length+')</span>'
        +(canManage&&t.status==='open'?'<button class="btn bol bsm" style="margin-left:auto" onclick="addParticipantW(this.dataset.tid)" data-tid="'+t.id+'">+ Ajouter</button>':'')
        +'</div><div style="padding:8px 0">'
        +((t.participants||[]).length===0?'<div class="td tsm" style="padding:8px 16px">Aucun inscrit.</div>':'')
        +(t.participants||[]).map(function(p,i){
          var mb=DB.members.find(function(m){return m.id===p.memberId;});
          var guestMb=DB.members.find(function(x){return x.id===p.memberId&&x.isGuest;});
          var isGuest=!!(p.house||guestMb);
          var guestHouse=p.house||(guestMb&&guestMb.guestHouse)||'';
          return'<div style="display:flex;align-items:center;gap:10px;padding:8px 16px;border-bottom:1px solid var(--b1)">'
            +'<div style="font-size:12px;font-weight:700;color:var(--gold);min-width:24px">'+(i+1)+'</div>'
            +(mb?avaHTML(mb,28):'<div style="width:28px;height:28px;border-radius:50%;background:var(--bg3);display:flex;align-items:center;justify-content:center;font-size:14px;color:var(--tx3)">'+(p.name||'?')[0].toUpperCase()+'</div>')
            +'<div style="flex:1">'
            +'<div style="font-size:13px;font-weight:600">'+(mb?esc(mb.username):esc(p.name||'Inconnu'))+(isGuest?'<span style="font-size:10px;background:rgba(201,162,39,.15);color:var(--gold);padding:1px 6px;border-radius:10px;border:1px solid rgba(201,162,39,.3);margin-left:6px">🎟️ Guest</span>':'')+'</div>'
            +(isGuest&&guestHouse?'<div style="font-size:11px;color:var(--tx3)">'+esc(guestHouse)+'</div>':'')
            +'</div>'
            +(canManage?'<button class="btn bred bsm" style="font-size:9px" data-tid="'+t.id+'" data-mid="'+p.memberId+'" onclick="removeParticipantW(this.dataset.tid,this.dataset.mid)">✕</button>':'')
            +'</div>';
        }).join('')
        +'</div></div>';
    }
  }
  // Bracket
  if(t.status!=='open'&&(t.bracket||[]).length>0){
    h+=renderBracket(t);
  } else if(canManage&&t.status==='open'&&(t.participants||[]).length>=2){
    h+='<div style="background:rgba(201,162,39,.08);border:1px solid var(--golddim);border-radius:3px;padding:16px;text-align:center">'
      +'<div style="font-size:13px;color:var(--gold);margin-bottom:10px">'+((t.participants||[]).length)+' participants inscrits — Prêt à démarrer</div>'
      +'<button class="btn bg" onclick="startTournamentW(this)" data-id="'+t.id+'">⚔️ Générer le bracket et démarrer</button>'
      +'</div>';
  }
  return h;
}

function renderBracket(t){
  var rounds=t.bracket||[];
  if(!rounds.length) return '';

  // Layout constants
  var cardW=160, cardH=64, roundGap=60, matchGap=24;

  // Calculate total SVG dimensions
  var maxMatches=rounds.length?rounds[0].matches.length:1;
  var totalH=maxMatches*(cardH+matchGap)+matchGap;
  var totalW=rounds.length*(cardW+roundGap)+roundGap;

  var svgLines='';
  var svgCards='';

  // Draw each round
  rounds.forEach(function(round,ri){
    var matchCount=round.matches.length;
    var totalRoundH=matchCount*(cardH+matchGap);
    var startY=(totalH-totalRoundH)/2;
    var x=roundGap+ri*(cardW+roundGap);

    // Round label
    svgCards+='<text x="'+(x+cardW/2)+'" y="20" text-anchor="middle" '
      +'font-size="10" font-weight="700" fill="#c9a227" letter-spacing="1">'
      +esc(round.label||('Tour '+(round.round+1)))+'</text>';

    round.matches.forEach(function(match,mi){
      var y=30+startY+mi*(cardH+matchGap);
      var cx=x+cardW/2, cy=y+cardH/2;

      // Draw connector lines to next round
      if(ri<rounds.length-1){
        var nextMatchIdx=Math.floor(mi/2);
        var nextRound=rounds[ri+1];
        var nextMatchCount=nextRound.matches.length;
        var nextTotalH=nextMatchCount*(cardH+matchGap);
        var nextStartY=(totalH-nextTotalH)/2;
        var nextX=roundGap+(ri+1)*(cardW+roundGap);
        var nextY=30+nextStartY+nextMatchIdx*(cardH+matchGap)+cardH/2;
        // Line from right edge of current card to midpoint
        var midX=x+cardW+roundGap/2;
        svgLines+='<polyline points="'+(x+cardW)+','+cy+' '+midX+','+cy+' '+midX+','+nextY+' '+nextX+','+nextY+'" '
          +'fill="none" stroke="rgba(201,162,39,.25)" stroke-width="1.5"/>';
      }

      // Resolve player names
      var p1=DB.members.find(function(m){return m.id===match.p1;})||{username:match.p1name||'TBD'};
      var p2=DB.members.find(function(m){return m.id===match.p2;})||{username:match.p2name||'TBD'};
      var w1=match.winner&&match.winner===match.p1;
      var w2=match.winner&&match.winner===match.p2;
      var isTBD=!match.p1||!match.p2;

      // Card background
      svgCards+='<rect x="'+x+'" y="'+y+'" width="'+cardW+'" height="'+cardH+'" rx="4" '
        +'fill="#0e1318" stroke="'+(match.winner?'rgba(102,187,106,.4)':'rgba(255,255,255,.08)')+'"/>';

      // Divider
      svgCards+='<line x1="'+x+'" y1="'+(y+cardH/2)+'" x2="'+(x+cardW)+'" y2="'+(y+cardH/2)+'" '
        +'stroke="rgba(255,255,255,.06)" stroke-width="1"/>';

      // P1 row
      if(w1) svgCards+='<rect x="'+x+'" y="'+y+'" width="'+cardW+'" height="'+(cardH/2)+'" rx="4" fill="rgba(102,187,106,.12)"/>';
      svgCards+='<text x="'+(x+10)+'" y="'+(y+20)+'" font-size="11" font-weight="'+(w1?'700':'400')+'" '
        +'fill="'+(w1?'#66bb6a':isTBD?'#555':'#e8dcc8')+'" clip-path="url(#clip'+ri+'_'+mi+'_1)">'
        +esc(p1.username.length>14?p1.username.slice(0,13)+'…':p1.username)+'</text>';
      if(match.score1!==null&&match.score1!==undefined)
        svgCards+='<text x="'+(x+cardW-8)+'" y="'+(y+20)+'" font-size="12" font-weight="700" '
          +'text-anchor="end" fill="'+(w1?'#66bb6a':'#b8a88a')+'">'+match.score1+'</text>';
      if(w1) svgCards+='<text x="'+(x+cardW-24)+'" y="'+(y+20)+'" font-size="10" fill="#66bb6a">🏆</text>';

      // P2 row
      if(w2) svgCards+='<rect x="'+x+'" y="'+(y+cardH/2)+'" width="'+cardW+'" height="'+(cardH/2)+'" rx="4" fill="rgba(102,187,106,.12)"/>';
      svgCards+='<text x="'+(x+10)+'" y="'+(y+cardH/2+20)+'" font-size="11" font-weight="'+(w2?'700':'400')+'" '
        +'fill="'+(w2?'#66bb6a':isTBD?'#555':'#e8dcc8')+'">'
        +esc(p2.username.length>14?p2.username.slice(0,13)+'…':p2.username)+'</text>';
      if(match.score2!==null&&match.score2!==undefined)
        svgCards+='<text x="'+(x+cardW-8)+'" y="'+(y+cardH/2+20)+'" font-size="12" font-weight="700" '
          +'text-anchor="end" fill="'+(w2?'#66bb6a':'#b8a88a')+'">'+match.score2+'</text>';
      if(w2) svgCards+='<text x="'+(x+cardW-24)+'" y="'+(y+cardH/2+20)+'" font-size="10" fill="#66bb6a">🏆</text>';

      // Enter score button (HTML overlay via foreignObject not reliable — use clickable rect)
      var canEdit=(HR('evenement')||HR('officier'))&&t.status==='ongoing'&&!match.winner&&match.p1&&match.p2;
      if(canEdit){
        svgCards+='<rect x="'+(x+cardW/2-30)+'" y="'+(y+cardH/2-10)+'" width="60" height="20" rx="3" '
          +'fill="#131920" stroke="rgba(201,162,39,.4)" cursor="pointer" '
        svgCards+='<rect x="'+(x+cardW/2-30)+'" y="'+(y+cardH/2-10)+'" width="60" height="20" rx="3" fill="#131920" stroke="rgba(201,162,39,.4)" cursor="pointer" data-tid="'+t.id+'" data-round="'+round.round+'" data-midx="'+match.matchIndex+'" onclick="enterScoreW(this.dataset.tid,this.dataset.round,this.dataset.midx)" />';
        svgCards+='<text x="'+(x+cardW/2)+'" y="'+(y+cardH/2+4)+'" text-anchor="middle" font-size="9" '
          +'fill="#c9a227" cursor="pointer" pointer-events="none">Entrer score</text>';
      }
    });
  });

  // Winner banner
  var lastRound=rounds[rounds.length-1];
  var finalMatch=lastRound&&lastRound.matches[0];
  var winner=finalMatch&&finalMatch.winner;
  var winnerMb=winner&&DB.members.find(function(m){return m.id===winner;});
  var winnerName=winnerMb?winnerMb.username:(finalMatch&&(finalMatch.winner===finalMatch.p1?finalMatch.p1name:finalMatch.p2name))||'';
  var winnerBanner=winner?'<div style="text-align:center;padding:16px;background:rgba(201,162,39,.1);border:1px solid var(--golddim);border-radius:3px;margin-bottom:12px">'
    +'<div style="font-size:24px">🏆</div>'
    +'<div style="font-size:16px;font-weight:700;color:var(--gold);font-family:Cinzel,serif">'+esc(winnerName)+'</div>'
    +'<div style="font-size:11px;color:var(--tx3)">Vainqueur du tournoi</div>'
    +'</div>':'';

  return '<div class="pan"><div class="ph"><span class="ptl">⚔️ Bracket</span></div>'
    +winnerBanner
    +'<div style="overflow-x:auto;padding:16px">'
    +'<svg width="'+totalW+'" height="'+totalH+'" xmlns="http://www.w3.org/2000/svg">'
    +'<defs><style>.bracket-text{font-family:inherit}</style></defs>'
    +svgLines+svgCards
    +'</svg></div></div>';
}
function registerTournament(el){var tid=typeof el==="string"?el:el.dataset.tid;
  var t=(DB.tournaments||[]).find(function(x){return x.id===tid;});
  if(!t||t.status!=='open') return;
  if((t.participants||[]).find(function(p){return p.memberId===CU.id;})){alert('Déjà inscrit.');return;}
  if((t.participants||[]).length>=(t.maxParticipants||16)){alert('Tournoi complet.');return;}
  t.participants=t.participants||[];
  t.participants.push({memberId:CU.id,name:CU.username,registeredAt:nowDate()});
  sbSaveTournament(t).then(function(){
    sbLoad().then(function(){
      var updated=(DB.tournaments||[]).find(function(x){return x.id===t.id;});
      window._calDetail={type:'tournament',data:updated||t};
      go('cal');
    });
  }).catch(function(e){console.warn(e);});
}

function unregisterTournament(el){var tid=typeof el==="string"?el:el.dataset.tid;
  var t=(DB.tournaments||[]).find(function(x){return x.id===tid;});
  if(!t||t.status!=='open') return;
  if(!confirm('Se désinscrire du tournoi ?')) return;
  t.participants=(t.participants||[]).filter(function(p){return p.memberId!==CU.id;});
  sbSaveTournament(t).then(function(){
    sbLoad().then(function(){
      var updated=(DB.tournaments||[]).find(function(x){return x.id===t.id;});
      window._calDetail={type:'tournament',data:updated||t};
      go('cal');
    });
  }).catch(function(e){console.warn(e);});
}

function addParticipantW(tid){
  var t=(DB.tournaments||[]).find(function(x){return x.id===tid;});
  if(!t) return;
  var alreadyIn=(t.participants||[]).map(function(p){return p.memberId;});
  var available=DB.members.filter(function(m){return alreadyIn.indexOf(m.id)<0;});
  OM('Ajouter un participant',
    '<div class="fg"><label class="fl">Membre</label><select class="fs" id="ap-mbr">'
    +available.map(function(m){return'<option value="'+m.id+'">'+esc(m.username)+'</option>';}).join('')
    +'</select></div>',
    [{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'Ajouter',cls:'btn bg',fn:function(){
      var mid=gVal('ap-mbr');
      var mb=DB.members.find(function(m){return m.id===mid;});
      if(!mb) return;
      t.participants=t.participants||[];
      t.participants.push({memberId:mid,name:mb.username,registeredAt:nowDate()});
      sbSaveTournament(t).then(function(){
        sbLoad().then(function(){
          var updated=(DB.tournaments||[]).find(function(x){return x.id===t.id;});
          CM();window._calDetail={type:'tournament',data:updated||t};go('cal');
        });
      }).catch(function(e){console.warn(e);});
    }}]);
}

function removeParticipantW(tid,mid){
  if(!confirm('Retirer ce participant du tournoi ?')) return;
  var t=(DB.tournaments||[]).find(function(x){return x.id===tid;});
  if(!t||!confirm('Retirer ce participant ?')) return;
  t.participants=(t.participants||[]).filter(function(p){return p.memberId!==mid;});
  sbSaveTournament(t).catch(function(e){console.warn(e);});
  window._calDetail={type:'tournament',data:t};
  go('cal');
}

function startTournamentW(el){
  var tid=el.dataset.id;
  var t=(DB.tournaments||[]).find(function(x){return x.id===tid;});
  if(!t) return;
  if(t.type==='team'){
    openTeamBuilder(t);
  } else {
    if(!confirm('Générer le bracket et démarrer le tournoi ?')) return;
    var parts=[].concat(t.participants||[]);
    for(var i=parts.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var tmp=parts[i];parts[i]=parts[j];parts[j]=tmp;}
    t.bracket=generateEliminationBracket(parts);
    t.status='ongoing';
    t.participants=parts;
    sbSaveTournament(t).catch(function(e){console.warn(e);});
    window._calDetail={type:'tournament',data:t};
    go('cal');
  }
}

function openTeamBuilderW(el){
  var t=(DB.tournaments||[]).find(function(x){return x.id===el.dataset.id;});
  if(t) openTeamBuilder(t);
}

function openTeamBuilder(t){
  var teamSize=t.teamSize||2;
  var participants=t.participants||[];
  var nbTeams=Math.floor(participants.length/teamSize);
  if(nbTeams<2){alert('Pas assez de participants pour former au moins 2 équipes de '+teamSize+' joueurs.');return;}

  // Initialiser les équipes si pas encore fait
  if(!t.teams||!t.teams.length){
    t.teams=[];
    for(var i=0;i<nbTeams;i++){
      t.teams.push({id:'team'+i,name:'Équipe '+(i+1),members:[]});
    }
  }

  renderTeamBuilder(t);
}

function renderTeamBuilder(t){
  var teamSize=t.teamSize||2;
  var participants=t.participants||[];
  var teams=t.teams||[];
  var sel=window._tbSelected||null; // ID joueur sélectionné

  // Membres non assignés
  var assignedIds=[];
  teams.forEach(function(team){team.members.forEach(function(m){assignedIds.push(m.memberId);});});
  var unassigned=participants.filter(function(p){return assignedIds.indexOf(p.memberId)<0;});

  var html='<div style="margin-bottom:12px;display:flex;gap:8px;align-items:center;flex-wrap:wrap">'
    +'<span style="font-size:11px;color:var(--tx3)">'+teamSize+'v'+teamSize+' — Cliquez un joueur puis une équipe pour l\'assigner.</span>'
    +'<button onclick="autoFillTeamsW(this)" data-tid="'+t.id+'" class="btn bol bsm" style="margin-left:auto">⚡ Auto-répartir</button>'
    +'</div>';

  // Non assignés
  html+='<div style="margin-bottom:14px"><div style="font-size:10px;font-weight:700;color:var(--tx3);letter-spacing:1px;margin-bottom:6px">NON ASSIGNÉS ('+unassigned.length+')</div>';
  html+='<div style="display:flex;flex-wrap:wrap;gap:6px">';
  unassigned.forEach(function(p){
    var m=DB.members.find(function(x){return x.id===p.memberId;});
    var isSelected=sel===p.memberId;
    html+='<div onclick="tbSelectPlayer(this)" data-tid="'+t.id+'" data-pid="'+p.memberId+'" style="cursor:pointer;border-radius:3px;padding:5px 10px;font-size:12px;display:flex;align-items:center;gap:6px;transition:all .15s;'
      +(isSelected?'background:var(--golddim);border:2px solid var(--gold);color:var(--gold);':'background:var(--bg2);border:2px solid var(--b2);color:var(--tx1);')
      +'">'
      +(m?avaHTML(m,18):'')
      +(m?esc(m.username):esc(p.name||p.memberId))
      +(isSelected?'<span style="font-size:10px">✓</span>':'')
      +'</div>';
  });
  html+='</div></div>';

  // Équipes
  html+='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:10px;margin-bottom:14px">';
  teams.forEach(function(team,ti){
    var isFull=team.members.length>=(teamSize);
    var canAdd=sel&&!isFull;
    html+='<div onclick="tbDropToTeam(this)" data-tid="'+t.id+'" data-ti="'+ti+'" style="background:var(--bg1);border:2px solid '+(canAdd?'var(--gold)':'var(--b2)')+';border-radius:4px;padding:10px;cursor:'+(canAdd?'pointer':'default')+';transition:border-color .15s">';
    html+='<input style="width:100%;background:transparent;border:none;border-bottom:1px solid var(--b2);color:var(--gold);font-family:Cinzel,serif;font-size:11px;font-weight:700;padding:2px 0;margin-bottom:8px" value="'+esc(team.name)+'" onclick="event.stopPropagation()" onchange="renameTeamW(this)" data-tid="'+t.id+'" data-ti="'+ti+'">';
    if(team.members.length===0){
      html+='<div style="font-size:11px;color:var(--tx3);text-align:center;padding:6px 0">'+(canAdd?'👆 Cliquer pour ajouter':'Vide')+'</div>';
    }
    team.members.forEach(function(p){
      var m=DB.members.find(function(x){return x.id===p.memberId;});
      html+='<div style="display:flex;align-items:center;gap:5px;margin-bottom:4px;font-size:11px;color:var(--tx1)">'
        +(m?avaHTML(m,16):'')
        +(m?esc(m.username):esc(p.name||p.memberId))
        +'<button onclick="tbRemovePlayer(this);event.stopPropagation()" data-tid="'+t.id+'" data-pid="'+p.memberId+'" data-ti="'+ti+'" style="margin-left:auto;background:none;border:none;color:var(--red3);cursor:pointer;font-size:11px;padding:0">✕</button>'
        +'</div>';
    });
    if(!isFull) html+='<div style="font-size:9px;color:var(--tx3);text-align:right;margin-top:4px">'+team.members.length+'/'+teamSize+'</div>';
    else html+='<div style="font-size:9px;color:#66bb6a;text-align:right;margin-top:4px">✅ Complet</div>';
    html+='</div>';
  });
  html+='</div>';

  var allFull=unassigned.length===0&&teams.every(function(team){return team.members.length>=teamSize;});

  OM('Formation des équipes — '+esc(t.title), html,
    [{lbl:'Annuler',cls:'bol',fn:function(){window._tbSelected=null;CM();}},
     {lbl:'+ Ajouter une équipe',cls:'btn bol',fn:function(){
       t.teams=t.teams||[];
       t.teams.push({id:'team'+Date.now(),name:'Équipe '+(t.teams.length+1),members:[]});
       window._tbSelected=null;
       renderTeamBuilder(t);
     }},
     {lbl:'⚔️ Générer le bracket',cls:'btn bg',fn:function(){
       if(unassigned.length>0){
         if(!confirm(unassigned.length+' joueur(s) non assigné(s). Continuer quand même ?')) return;
       }
       window._tbSelected=null;
       CM();
       var teamParts=t.teams.filter(function(team){return team.members.length>0;}).map(function(team){
         return{memberId:team.id,name:team.name,teamData:team};
       });
       if(teamParts.length<2){alert('Il faut au moins 2 équipes.');return;}
       t.bracket=generateEliminationBracket(teamParts);
       t.status='ongoing';
       sbSaveTournament(t).catch(function(e){console.warn(e);});
       window._calDetail={type:'tournament',data:t};
       go('cal');
     }}]);
}

function tbSelectPlayer(el){
  var pid=el.dataset.pid;
  var t=(DB.tournaments||[]).find(function(x){return x.id===el.dataset.tid;});
  if(!t) return;
  window._tbSelected=(window._tbSelected===pid)?null:pid;
  renderTeamBuilder(t);
}

function tbDropToTeam(el){
  if(!window._tbSelected) return;
  var t=(DB.tournaments||[]).find(function(x){return x.id===el.dataset.tid;});
  if(!t) return;
  var ti=parseInt(el.dataset.ti);
  var team=t.teams[ti];
  if(!team||team.members.length>=(t.teamSize||2)) return;
  var p=(t.participants||[]).find(function(x){return x.memberId===window._tbSelected;});
  if(!p) return;
  // Vérifier pas déjà dans une équipe
  var alreadyIn=false;
  t.teams.forEach(function(te){te.members.forEach(function(m){if(m.memberId===p.memberId)alreadyIn=true;});});
  if(alreadyIn) return;
  team.members.push(p);
  window._tbSelected=null;
  renderTeamBuilder(t);
}

function tbRemovePlayer(btn){
  var t=(DB.tournaments||[]).find(function(x){return x.id===btn.dataset.tid;});
  if(!t) return;
  var ti=parseInt(btn.dataset.ti);
  t.teams[ti].members=t.teams[ti].members.filter(function(m){return m.memberId!==btn.dataset.pid;});
  window._tbSelected=null;
  renderTeamBuilder(t);
}

function autoFillTeamsW(btn){
  var t=(DB.tournaments||[]).find(function(x){return x.id===btn.dataset.tid;});
  if(!t) return;
  var teamSize=t.teamSize||2;
  var participants=[].concat(t.participants||[]);
  // Mélanger
  for(var i=participants.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var tmp=participants[i];participants[i]=participants[j];participants[j]=tmp;}
  // Créer les équipes
  var nbTeams=Math.floor(participants.length/teamSize);
  if(nbTeams<2){alert('Pas assez de participants pour au moins 2 équipes.');return;}
  t.teams=[];
  for(var k=0;k<nbTeams;k++){
    t.teams.push({id:'team'+Date.now()+k,name:'Équipe '+(k+1),members:participants.slice(k*teamSize,(k+1)*teamSize)});
  }
  window._tbSelected=null;
  renderTeamBuilder(t);
}


function renameTeamW(inp){
  var t=(DB.tournaments||[]).find(function(x){return x.id===inp.dataset.tid;});
  if(!t) return;
  var ti=parseInt(inp.dataset.ti);
  if(t.teams[ti]) t.teams[ti].name=inp.value;
}

function generateEliminationBracket(participants){
  // Pad to next power of 2
  var n=participants.length;
  var size=1;while(size<n)size*=2;
  var padded=participants.slice();
  while(padded.length<size) padded.push(null); // byes
  var rounds=[];
  var current=padded;
  var roundNum=0;
  while(current.length>1){
    var matches=[];
    var roundLabels=['Finale','Demi-finales','Quarts de finale','8ème de finale','16ème de finale'];
    var totalRounds=Math.log2(size);
    var label=roundLabels[totalRounds-roundNum-1]||('Tour '+(roundNum+1));
    for(var i=0;i<current.length;i+=2){
      var p1=current[i],p2=current[i+1];
      var match={
        matchIndex:matches.length, round:roundNum,
        p1:p1?p1.memberId:null, p1name:p1?p1.name:'BYE',
        p2:p2?p2.memberId:null, p2name:p2?p2.name:'BYE',
        score1:null, score2:null, winner:null
      };
      // Auto-advance byes
      if(!p1){match.winner=p2?p2.memberId:null;match.score1=0;match.score2=1;}
      else if(!p2){match.winner=p1.memberId;match.score1=1;match.score2=0;}
      matches.push(match);
    }
    rounds.push({round:roundNum,label:label,matches:matches});
    // Next round participants = winners
    current=matches.map(function(m){
      if(m.winner){return participants.find(function(p){return p&&p.memberId===m.winner;})||null;}
      return {memberId:'TBD_'+roundNum+'_'+m.matchIndex,name:'TBD'};
    });
    roundNum++;
  }
  return rounds;
}

function enterScoreW(tid,roundNum,matchIdx){
  var t=(DB.tournaments||[]).find(function(x){return x.id===tid;});
  if(!t) return;
  var round=t.bracket[roundNum];
  var match=round&&round.matches[matchIdx];
  if(!match) return;
  var p1=DB.members.find(function(m){return m.id===match.p1;})||{username:match.p1name||'Joueur 1'};
  var p2=DB.members.find(function(m){return m.id===match.p2;})||{username:match.p2name||'Joueur 2'};
  OM('Entrer le score',
    '<div style="font-size:13px;font-weight:700;color:var(--tx1);margin-bottom:12px;text-align:center">'+esc(p1.username)+' vs '+esc(p2.username)+'</div>'
    +'<div class="fr2">'
    +'<div class="fg"><label class="fl">Score '+esc(p1.username)+'</label><input class="fi" type="number" id="sc1" value="0" min="0"></div>'
    +'<div class="fg"><label class="fl">Score '+esc(p2.username)+'</label><input class="fi" type="number" id="sc2" value="0" min="0"></div>'
    +'</div>',
    [{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'Valider',cls:'btn bg',fn:function(){
      var s1=parseInt(gVal('sc1'))||0;
      var s2=parseInt(gVal('sc2'))||0;
      if(s1===s2){alert('Pas de match nul — un vainqueur doit être désigné.');return;}
      match.score1=s1; match.score2=s2;
      match.winner=s1>s2?match.p1:match.p2;
      // Advance winner to next round
      advanceBracket(t,roundNum,matchIdx,match.winner);
      // Check if tournament finished
      var lastRound=t.bracket[t.bracket.length-1];
      if(lastRound&&lastRound.matches.every(function(m){return m.winner;})){
        t.status='finished';
        cleanupGuestAccounts(t.id);
      }
      sbSaveTournament(t).catch(function(e){console.warn(e);});
      CM();window._calDetail={type:'tournament',data:t};go('cal');
    }}]);
}

function advanceBracket(t,roundNum,matchIdx,winnerId){
  if(roundNum+1>=t.bracket.length) return;
  var nextRound=t.bracket[roundNum+1];
  var nextMatchIdx=Math.floor(matchIdx/2);
  var nextMatch=nextRound&&nextRound.matches[nextMatchIdx];
  if(!nextMatch) return;
  var winnerPart=(t.participants||[]).find(function(p){return p.memberId===winnerId;});
  var winnerName=winnerPart?winnerPart.name:winnerId;
  if(matchIdx%2===0){nextMatch.p1=winnerId;nextMatch.p1name=winnerName;}
  else{nextMatch.p2=winnerId;nextMatch.p2name=winnerName;}
}

